const BlogListPage = () => {
  const [selectedCategory, setSelectedCategory] = useState('Kõik');
  const [searchQuery, setSearchQuery] = useState('');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const postsPerPage = 6;

  const scrollToSection = () => {};

  const categories = useMemo(() => {
    const cats = Array.from(new Set(blogPosts.map(post => post.category)));
    return ['Kõik', ...cats.sort()];
  }, []);

  const filteredPosts = useMemo(() => {
    return blogPosts.filter(post => {
      const matchesCategory = selectedCategory === 'Kõik' || post.category === selectedCategory;
      const matchesSearch = !searchQuery || 
        post.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        post.excerpt.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery]);

  const paginatedPosts = useMemo(() => {
    const startIndex = (currentPage - 1) * postsPerPage;
    return filteredPosts.slice(startIndex, startIndex + postsPerPage);
  }, [filteredPosts, currentPage, postsPerPage]);

  return (
    <div className="min-h-screen bg-[#030509] text-slate-100 antialiased">
      <Helmet>
        <title>Blogi - Nisbel Autostuudio | Autohoolduse nõuanded ja juhised</title>
        <meta 
          name="description" 
          content="Leia kasulikke autohoolduse nõuandeid, juhiseid ja eksperditeadmisi Nisbel Autostuudio blogist. Mootorihooldus, veermik, diagnostika ja palju muud." 
        />
      </Helmet>

      {/* Header Navigation */}
      <motion.div
        className="fixed inset-x-0 top-0 z-50 flex justify-center px-4 pt-6"
        initial={{ opacity: 0, y: -40 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8, ease: 'easeOut' }}
      >
        <div className="flex w-full max-w-6xl items-center justify-between rounded-full border border-white/10 bg-[#05070F]/80 px-5 py-3 shadow-2xl shadow-black/30 backdrop-blur-2xl">
          <Link to="/" className="flex items-center">
            <img 
              src="/nisbel-logo-dark-mode.png" 
              alt="Nisbel Autostuudio - Premium autohooldus Tallinnas" 
              className="h-12"
            />
          </Link>
          <nav className="hidden items-center gap-6 text-sm text-white/60 md:flex">
            <Link to="/" className="transition-colors duration-300 hover:text-white">
              Avaleht
            </Link>
            <span className="text-white">Blogi</span>
          </nav>
          <Link
            to="/#kontakt"
            className="rounded-full bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.3em] text-[#05070F] transition hover:bg-slate-200"
          >
            Broneeri
          </Link>
        </div>
      </motion.div>

      {/* Background */}
      <div className="relative isolate">
        <div className="absolute inset-0 -z-10 bg-gradient-to-b from-[#050a1c] via-[#02040b] to-[#010206]" />
        <div aria-hidden="true" className="absolute inset-0 -z-10">
          <motion.span
            className="absolute left-[15%] top-[20%] size-[500px] rounded-full bg-gradient-to-r from-[#5ee7df]/20 to-[#b490ca]/20 blur-[120px]"
            animate={{ opacity: [0.15, 0.35, 0.2], scale: [0.9, 1.05, 0.95] }}
            transition={{ duration: 9, repeat: Infinity, repeatType: 'mirror' }}
          />
          <motion.span
            className="absolute right-[10%] top-[60%] size-[400px] rounded-full bg-gradient-to-l from-[#b490ca]/15 to-[#5ee7df]/15 blur-[100px]"
            animate={{ opacity: [0.2, 0.4, 0.25], scale: [0.95, 1.05, 0.9] }}
            transition={{ duration: 11, repeat: Infinity, repeatType: 'mirror', delay: 2 }}
          />
        </div>
        {/* Header Section */}
        <section className="relative overflow-hidden px-4 pt-36 pb-16">
          <div className="mx-auto max-w-6xl">
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.8 }}
              className="space-y-8"
            >
              <Link 
                to="/" 
                className="inline-flex items-center gap-2 text-white/60 hover:text-white transition-colors text-sm"
              >
                <ArrowLeft size={16} />
                Tagasi avalehele
              </Link>
              
              <div className="inline-flex items-center gap-3 rounded-full border border-white/10 bg-white/5 px-4 py-2 text-[0.65rem] uppercase tracking-[0.5em] text-white/70">
                <span className="size-2 rounded-full bg-gradient-to-r from-[#5ee7df] to-[#b490ca]" />
                Nisbel Blogi 2025
              </div>
              
              <h1 className="text-4xl font-light leading-tight text-white md:text-6xl">
                Autohoolduse teadmised ja nõuanded
              </h1>
              <p className="max-w-2xl text-base text-white/70 md:text-lg">
                Ekspertide poolt kirjutatud artiklid mootorihooldusest, veermikust, diagnostikast ja autohoolduse parimatest tavadest.
              </p>
            </motion.div>
          </div>
        </section>

        {/* Search & Filters */}
        <div className="max-w-6xl mx-auto px-6 py-8">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.2 }}
          >
            <div className="mb-6">
              <div className="relative">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-white/40" size={20} />
                <input
                  type="text"
                  placeholder="Otsi artikleid..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-12 pr-4 py-3 rounded-full border border-white/10 bg-white/5 text-white placeholder:text-white/40 focus:border-white/20 focus:bg-white/10 outline-none transition-all backdrop-blur-sm"
                />
              </div>
            </div>

            {/* Categories */}
            <div className="flex gap-2 overflow-x-auto pb-2 mb-6">
              {categories.map((category) => (
                <button
                  key={category}
                  onClick={() => setSelectedCategory(category)}
                  className={`px-4 py-2 rounded-full whitespace-nowrap text-xs uppercase tracking-wider font-medium transition-all ${
                    selectedCategory === category
                      ? 'bg-white text-[#05070F]'
                      : 'border border-white/10 bg-white/5 text-white/60 hover:bg-white/10 hover:text-white'
                  }`}
                >
                  {category}
                </button>
              ))}
            </div>

            <p className="text-sm text-white/50 mb-8">
              {filteredPosts.length} {filteredPosts.length === 1 ? 'artikkel' : 'artiklit'}
            </p>
          </motion.div>

          {/* Blog List */}
                    <motion.div 
                      className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6"
                      initial="hidden"
                      animate="visible"
                      variants={{
                        hidden: { opacity: 0 },
                        visible: {
                          opacity: 1,
                          transition: { staggerChildren: 0.08 }
                        }
                      }}
                    >
                      {paginatedPosts.map((post, index) => (
                        <motion.div
                          key={post.slug}
                          variants={{
                            hidden: { opacity: 0, y: 20 },
                            visible: { opacity: 1, y: 0 }
                          }}
                        >
                          <Link 
                            to={`/blog/${post.slug}`}
                            className="block group h-full"
                          >
                            <article className="h-full border border-white/10 rounded-2xl p-6 hover:border-white/20 hover:bg-white/5 transition-all duration-300 backdrop-blur-sm bg-white/[0.02] flex flex-col">
                              <div className="flex flex-col gap-4 flex-1">
                                <div className="flex flex-wrap items-center gap-2 text-xs text-white/50">
                                  <span className="inline-flex items-center gap-1.5 px-2 py-1 rounded-full bg-white/5 border border-white/10">
                                    <Tag size={12} />
                                    {post.category}
                                  </span>
                                  <span className="inline-flex items-center gap-1.5">
                                    <Calendar size={12} />
                                    {new Date(post.publishedAt).toLocaleDateString('et-EE', {
                                      day: 'numeric',
                                      month: 'short',
                                      year: 'numeric'
                                    })}
                                  </span>
                                  <span className="inline-flex items-center gap-1.5">
                                    <Clock size={12} />
                                    {post.readTime}
                                  </span>
                                </div>
                                
                                <h2 className="text-lg font-light text-white mb-2 group-hover:text-white/80 transition-colors leading-snug">
                                  {post.title}
                                </h2>
                                
                                <p className="text-white/60 leading-relaxed text-sm flex-1">
                                  {post.excerpt}
                                </p>
                              </div>
                            </article>
                          </Link>
                        </motion.div>
                      ))}
                    </motion.div>
          
                    {/* Pagination Controls */}
                    <div className="flex justify-center mt-12">
                      <div className="flex items-center gap-2">
                        <button
                          onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                          disabled={currentPage === 1}
                          className="px-4 py-2 rounded-full border border-white/10 bg-white/5 text-white/60 hover:bg-white/10 hover:text-white disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                          Eelmine
                        </button>
                        <span className="text-white/60">
                          Leht {currentPage} / {Math.ceil(filteredPosts.length / postsPerPage)}
                        </span>
                        <button
                          onClick={() => setCurrentPage(p => Math.min(Math.ceil(filteredPosts.length / postsPerPage), p + 1))}
                          disabled={currentPage === Math.ceil(filteredPosts.length / postsPerPage)}
                          className="px-4 py-2 rounded-full border border-white/10 bg-white/5 text-white/60 hover:bg-white/10 hover:text-white disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                          Järgmine
                        </button>
                      </div>
                    </div>
          
          {/* No results */}
          {filteredPosts.length === 0 && (
            <div className="text-center py-12">
              <p className="text-lg text-white/60">
                Otsingu tulemusi ei leitud. Proovi teist otsingusõna või kategooriat.
              </p>
            </div>
          )}
        </div>

        {/* CTA Section */}
        <section className="relative px-4 py-24 mt-12">
          <div className="mx-auto max-w-4xl text-center">
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.8 }}
              className="space-y-6"
            >
              <h2 className="text-3xl font-light text-white md:text-4xl">
                Vajad abi autohooldusega?
              </h2>
              <p className="text-white/70 text-lg">
                Broneeri aeg meie stuudios või helista meile nõu saamiseks
              </p>
              <div className="flex flex-col sm:flex-row gap-4 justify-center pt-4">
                <Link 
                  to="/#kontakt"
                  className="inline-flex items-center justify-center px-6 py-3 rounded-full bg-white text-[#05070F] font-medium hover:bg-slate-200 transition-colors text-sm uppercase tracking-wider"
                >
                  Broneeri aeg
                </Link>
                <a 
                  href="tel:+37256846555"
                  className="inline-flex items-center justify-center px-6 py-3 rounded-full border border-white/20 bg-white/5 text-white font-medium hover:bg-white/10 transition-colors text-sm uppercase tracking-wider"
                >
                  Helista +372 5684 6555
                </a>
              </div>
            </motion.div>
          </div>
        </section>

        {/* Footer */}
        <footer className="border-t border-white/10 py-8">
          <div className="max-w-6xl mx-auto px-6 text-center text-white/50 text-sm">
            <p>© 2025 Nisbel Autostuudio. Kõik õigused kaitstud.</p>
          </div>
        </footer>
      </div>
    </div>
  );
};

export default BlogListPage;
