import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';
import { motion } from 'framer-motion';
import { ArrowLeft, Calendar, Clock, Tag, Share2 } from 'lucide-react';

export const BlogPostLayout = ({ 
  title, 
  description, 
  category, 
  publishedAt, 
  readTime,
  children,
  slug,
  featuredImage,
  posts
}) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const scrollToSection = () => {};

  const shareUrl = typeof window !== 'undefined' ? window.location.href : '';
  
  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: title,
          text: description,
          url: shareUrl,
        });
      } catch (err) {
        console.log('Error sharing:', err);
      }
    }
  };

  return (
    <div className="min-h-screen bg-[#030509] text-slate-100 antialiased">
      <Helmet>
        <title>{title} - Nisbel Autostuudio</title>
        <meta name="description" content={description} />
        <meta property="og:type" content="article" />
        <meta property="og:title" content={title} />
        <meta property="og:description" content={description} />
        <meta property="og:url" content={shareUrl} />
      </Helmet>

      {/* Header Navigation */}
      <motion.div
        className="fixed inset-x-0 top-0 z-50 flex justify-center px-4 pt-6"
        initial={{ opacity: 0, y: -40 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8, ease: 'easeOut' }}
      >
        <div className="flex w-full max-w-6xl items-center justify-between rounded-full border border-white/10 bg-[#05070F]/80 px-5 py-3 shadow-2xl shadow-black/30 backdrop-blur-2xl">
          <Link
            to="/"
            className="text-xs font-semibold uppercase tracking-[0.45em] text-white"
          >
            NISBEL
          </Link>
          <nav className="hidden items-center gap-6 text-sm text-white/60 md:flex">
            <Link to="/" className="transition-colors duration-300 hover:text-white">
              Avaleht
            </Link>
            <Link to="/blog" className="transition-colors duration-300 hover:text-white">
              Blogi
            </Link>
          </nav>
          <Link
            to="/#kontakt"
            className="rounded-full bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.3em] text-[#05070F] transition hover:bg-slate-200"
          >
            Broneeri
          </Link>
        </div>
      </motion.div>

      {/* Background */}
      <div className="relative isolate">
        <div className="absolute inset-0 -z-10 bg-gradient-to-b from-[#050a1c] via-[#02040b] to-[#010206]" />
        <div aria-hidden="true" className="absolute inset-0 -z-10">
          <motion.span
            className="absolute left-[15%] top-[20%] size-[500px] rounded-full bg-gradient-to-r from-[#5ee7df]/20 to-[#b490ca]/20 blur-[120px]"
            animate={{ opacity: [0.15, 0.35, 0.2], scale: [0.9, 1.05, 0.95] }}
            transition={{ duration: 9, repeat: Infinity, repeatType: 'mirror' }}
          />
          <motion.span
            className="absolute right-[10%] top-[60%] size-[400px] rounded-full bg-gradient-to-l from-[#b490ca]/15 to-[#5ee7df]/15 blur-[100px]"
            animate={{ opacity: [0.2, 0.4, 0.25], scale: [0.95, 1.05, 0.9] }}
            transition={{ duration: 11, repeat: Infinity, repeatType: 'mirror', delay: 2 }}
          />
        </div>

        <article className="relative max-w-4xl mx-auto px-6 py-24 pt-36">
          {/* Breadcrumb */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="mb-8"
          >
            <Link 
              to="/blog" 
              className="inline-flex items-center gap-2 text-white/60 hover:text-white transition-colors text-sm"
            >
              <ArrowLeft size={16} />
              Tagasi blogisse
            </Link>
          </motion.div>

          {/* Metadata */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.1 }}
            className="flex flex-wrap items-center gap-3 text-xs text-white/50 mb-6"
          >
            <span className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-white/5 border border-white/10 text-white/70">
              <Tag size={12} />
              {category}
            </span>
            <span className="inline-flex items-center gap-1.5">
              <Calendar size={12} />
              {new Date(publishedAt).toLocaleDateString('et-EE', {
                day: 'numeric',
                month: 'short',
                year: 'numeric'
              })}
            </span>
            <span className="inline-flex items-center gap-1.5">
              <Clock size={12} />
              {readTime}
            </span>
          </motion.div>

          {/* Title */}
          <motion.h1
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.2 }}
            className="text-3xl md:text-5xl font-light text-white mb-6 leading-tight"
          >
            {title}
          </motion.h1>

          {/* Description */}
          <motion.p
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.3 }}
            className="text-lg text-white/70 leading-relaxed mb-12 pb-8 border-b border-white/10"
          >
            {description}
          </motion.p>

          {featuredImage && (
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, delay: 0.4 }}
              className="mb-12"
            >
              <img src={featuredImage} alt={title} className="rounded-lg w-full" />
            </motion.div>
          )}

          {/* Content */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.4 }}
            className="prose prose-invert max-w-none"
          >
            {children}
          </motion.div>

          <ShareButtons title={title} url={shareUrl} />

          {posts && (
            <div className="mt-16 pt-8 border-t border-white/10">
              <h3 className="text-2xl font-light text-white mb-6">Seotud postitused</h3>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {posts
                  .filter(p => p.category === category && p.slug !== slug)
                  .slice(0, 3)
                  .map(post => (
                    <Link key={post.slug} to={`/blog/${post.slug}`} className="block group">
                      <article className="h-full border border-white/10 rounded-2xl p-6 hover:border-white/20 hover:bg-white/5 transition-all duration-300 backdrop-blur-sm bg-white/[0.02]">
                        <h4 className="font-light text-white mb-2 group-hover:text-white/80 transition-colors leading-snug">
                          {post.title}
                        </h4>
                        <p className="text-white/60 leading-relaxed text-sm">
                          {post.excerpt}
                        </p>
                      </article>
                    </Link>
                  ))}
              </div>
            </div>
          )}

          {/* CTA at bottom */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 0.8 }}
            className="mt-16 pt-8 border-t border-white/10"
          >
            <div className="border border-white/10 rounded-2xl p-8 bg-white/[0.02] backdrop-blur-sm">
              <h3 className="text-2xl font-light text-white mb-3">
                Vajad abi selle teenusega?
              </h3>
              <p className="text-white/70 mb-6">
                Broneeri aeg meie stuudios või helista meile nõu saamiseks
              </p>
              <div className="flex flex-col sm:flex-row gap-3">
                <Link 
                  to="/#kontakt"
                  className="inline-flex items-center justify-center px-6 py-3 rounded-full bg-white text-[#05070F] font-medium hover:bg-slate-200 transition-colors text-sm uppercase tracking-wider"
                >
                  Broneeri aeg
                </Link>
                <a 
                  href="tel:+37256846555"
                  className="inline-flex items-center justify-center px-6 py-3 rounded-full border border-white/20 bg-white/5 text-white font-medium hover:bg-white/10 transition-colors text-sm uppercase tracking-wider"
                >
                  Helista +372 5684 6555
                </a>
              </div>
            </div>
          </motion.div>
        </article>

        {/* Footer */}
        <footer className="border-t border-white/10 py-8">
          <div className="max-w-6xl mx-auto px-6 text-center text-white/50 text-sm">
            <p>© 2025 Nisbel Autostuudio. Kõik õigused kaitstud.</p>
          </div>
        </footer>
      </div>
    </div>
  );
};

// Simple content components for blog posts
export const BlogSection = ({ title, children }) => (
  <section className="mb-10">
    {title && (
      <h2 className="text-2xl md:text-3xl font-light text-white mb-6">
        {title}
      </h2>
    )}
    {children}
  </section>
);

export const BlogParagraph = ({ children }) => (
  <p className="text-white/70 leading-relaxed mb-6 text-base">
    {children}
  </p>
);

export const BlogList = ({ items, ordered = false }) => {
  const Tag = ordered ? 'ol' : 'ul';
  return (
    <Tag className={`space-y-3 mb-8 ${ordered ? 'list-decimal' : 'list-disc'} list-inside text-white/70`}>
      {items.map((item, index) => (
        <li key={index} className="leading-relaxed pl-2">{item}</li>
      ))}
    </Tag>
  );
};

export const BlogHighlight = ({ children, type = 'info' }) => {
  const styles = {
    info: 'bg-blue-500/10 border-blue-500/30',
    warning: 'bg-yellow-500/10 border-yellow-500/30',
    tip: 'bg-green-500/10 border-green-500/30',
  };

  return (
    <div className={`border-l-4 ${styles[type]} p-5 mb-8 rounded-r-lg backdrop-blur-sm`}>
      <div className="text-white/80 text-sm leading-relaxed">
        {children}
      </div>
    </div>
  );
};

export const BlogSubheading = ({ children }) => (
  <h3 className="text-xl font-light text-white mb-4 mt-8">
    {children}
  </h3>
);

export const BlogStrong = ({ children }) => (
  <strong className="font-medium text-white">
    {children}
  </strong>
);

const ShareButtons = ({ title, url }) => {
  const encodedTitle = encodeURIComponent(title);
  const encodedUrl = encodeURIComponent(url);

  const networks = {
    facebook: `https://www.facebook.com/sharer/sharer.php?u=${encodedUrl}`,
    twitter: `https://twitter.com/intent/tweet?url=${encodedUrl}&text=${encodedTitle}`,
    linkedin: `https://www.linkedin.com/shareArticle?mini=true&url=${encodedUrl}&title=${encodedTitle}`,
  };

  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: title,
          url: url,
        });
      } catch (err) {
        console.log('Error sharing:', err);
      }
    }
  };

  return (
    <div className="flex items-center gap-4 mt-8">
      <span className="text-sm text-white/70">Jaga postitust:</span>
      <div className="flex items-center gap-2">
        {navigator.share && (
          <button
            onClick={handleShare}
            className="p-2 rounded-full bg-white/10 hover:bg-white/20 transition-colors"
          >
            <Share2 size={16} />
          </button>
        )}
        <a href={networks.facebook} target="_blank" rel="noopener noreferrer" className="p-2 rounded-full bg-white/10 hover:bg-white/20 transition-colors">
          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor"><path d="M18 2h-3a5 5 0 0 0-5 5v3H7v4h3v8h4v-8h3l1-4h-4V7a1 1 0 0 1 1-1h3z"></path></svg>
        </a>
        <a href={networks.twitter} target="_blank" rel="noopener noreferrer" className="p-2 rounded-full bg-white/10 hover:bg-white/20 transition-colors">
          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor"><path d="M22 4s-.7 2.1-2 3.4c1.6 1.4 2.8 3.2 3 5.2-1.4 1-3.2 2.2-5.2 2.7-.2 3.2-2.2 5.7-5 6.8-1.5.6-3.2.8-4.8.6-1.6-.2-3.2-.8-4.6-1.8-2.2-1.6-3.8-4-4.2-6.6-.4-2.6.2-5.2 1.6-7.4 1.4-2.2 3.6-3.8 6.2-4.4 2.6-.6 5.2-.2 7.4 1.2 2.2 1.4 3.8 3.6 4.4 6.2.2.8.3 1.6.3 2.4 0 .2 0 .4-.1.6.2-.2.4-.4.6-.6.8-.8 1.6-1.4 2.4-2 .2-.2.4-.3.6-.4.2-.1.4-.1.6-.1z"></path></svg>
        </a>
        <a href={networks.linkedin} target="_blank" rel="noopener noreferrer" className="p-2 rounded-full bg-white/10 hover:bg-white/20 transition-colors">
          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor"><path d="M16 8a6 6 0 0 1 6 6v7h-4v-7a2 2 0 0 0-2-2 2 2 0 0 0-2 2v7h-4v-7a6 6 0 0 1 6-6z"></path><rect width="4" height="12" x="2" y="9"></rect><circle cx="4" cy="4" r="2"></circle></svg>
        </a>
      </div>
    </div>
  );
};

