import React from 'react';
import {
  BlogPostLayout,
  BlogSection,
  BlogParagraph,
  BlogStrong,
} from '../../src/components/BlogPostLayout';

export default function BlogKarterituulutusPcv() {
  return (
    <BlogPostLayout
      title="Karterituulutus (PCV): väike sõlm, mis paneb otsustama õlikulu ja tihendite saatuse"
      description="Selgitame, miks PCV-süsteemi hooldus on kriitiline: kuidas ummistunud karterituulutus tekitab õlilekkeid, tõstab rõhku ja lõhub tihendeid."
      category="Mootorihooldus"
      publishedAt="2024-11-15"
      readTime="5 min"
      slug="karterituulutus-pcv"
      featuredImage="/autohooldus-tallinnas-premium.webp"
    >
      <header>
            
            <h2>Alternatiivsed pealkirjad</h2>
            <ul>
              <li>PCV-süsteem: miks ummistunud karterituulutus hävitab su tihendid?</li>
              <li>Karterituulutus ja õlikulu: nähtamatu süüdlane, mida peaaegu keegi ei hoolda</li>
              <li>Väike detail, suur mõju: karterituulutus (PCV) ja mootorikahjud</li>
            </ul>
            <BlogParagraph>
              Karterituulutus ehk PCV on üks alahinnatumaid süsteeme mootoris. Kui see ummistub või jääb hooldamata, tõuseb karteris rõhk, õli pressib tihenditest välja ja mootor hakkab “tossama”. Enamasti avastatakse see alles siis, kui leked on juba käes.
            </BlogParagraph>
          </header>

          <BlogSection title="Kuidas PCV-süsteem töötab ja miks see oluline on?">
            <BlogParagraph>
              PCV (Positive Crankcase Ventilation) juhib karterigaasid kontrollitult tagasi sisselaskesse, hoides <BlogStrong>rõhu tasakaalus ja õlikulu kontrolli all</BlogStrong>.
            </BlogParagraph>
            <ul>
              <li>normaalne karterirõhk;</li>
              <li>stabiilne tühikäik ja segu moodustumine;</li>
              <li>väiksem õlilekke ja õlikulu risk.</li>
            </ul>
          </BlogSection>

          <BlogSection title="Mis juhtub, kui karterituulutus ummistub?">
            <ul>
              <li><BlogStrong>Karterirõhk tõuseb:</BlogStrong> liigne rõhk pressib õli välja nõrgematest tihenditest – klapikambrikaan, karteri tihend, väntvõlli simmerid.</li>
              <li><BlogStrong>Tihendite lekked:</BlogStrong> algul väike niiskus, hiljem juba arvestatav õlileke.</li>
              <li><BlogStrong>Õli sisselaskes ja tossamine:</BlogStrong> õli jõuab põlemiskambrisse, suureneb õlikulu ja tekib sinakas suits.</li>
              <li><BlogStrong>Ebaühtlane töö:</BlogStrong> vale rõhk mõjutab segu, mootor võib hakata võdisema.</li>
            </ul>
          </BlogSection>

            <BlogSection title="Miks PCV-süsteemi peaaegu kunagi ei hooldata?">
            <BlogParagraph>
              PCV on peidus ja <BlogStrong>ükski "lihtsalt õlivahetus" seda ei kata</BlogStrong>. Tegelikkuses tasub ventiili, voolikuid ja kanaleid kontrollida iga <BlogStrong>80 000–120 000 km</BlogStrong> järel.
            </BlogParagraph>
          </BlogSection>

            <BlogSection title="Kahtlustad ummistunud karterituulutust?">
            <BlogParagraph>
              <a href="/kontakt">Võta ühendust Nisbeliga</a>, teeme mootorile sihtdiagnostika ja hindame PCV-süsteemi seisukorda.
            </BlogParagraph>
          </BlogSection>
    </BlogPostLayout>
  );
}
