import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence, Reorder } from 'framer-motion';
import { 
  Calendar, Clock, Car, User, Mail, Phone, CheckCircle, XCircle, 
  MessageSquare, TrendingUp, Users, Activity, Eye, EyeOff, X, GripVertical,
  RefreshCw, Download, Filter, Search, BarChart3, Bell, Settings,
  ChevronDown, ChevronUp, AlertCircle, CheckCircle2, Clock4
} from 'lucide-react';
import axios from 'axios';

const BACKEND_URL = import.meta.env.VITE_API_URL || 'http://localhost:3001';
const GA_MEASUREMENT_ID = import.meta.env.VITE_GA_MEASUREMENT_ID || '';

// Sound notification utility
const playNotificationSound = () => {
  try {
    const audioContext = new (window.AudioContext || window.webkitAudioContext)();
    const oscillator = audioContext.createOscillator();
    const gainNode = audioContext.createGain();
    
    oscillator.connect(gainNode);
    gainNode.connect(audioContext.destination);
    
    oscillator.frequency.value = 800;
    oscillator.type = 'sine';
    
    gainNode.gain.setValueAtTime(0.3, audioContext.currentTime);
    gainNode.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + 0.5);
    
    oscillator.start(audioContext.currentTime);
    oscillator.stop(audioContext.currentTime + 0.5);
  } catch (error) {
    console.error('Failed to play notification sound:', error);
  }
};

function AdminDashboard() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userRole, setUserRole] = useState('');
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loginError, setLoginError] = useState('');
  const [bookings, setBookings] = useState([]);
  const [selectedBooking, setSelectedBooking] = useState(null);
  const [chatMessages, setChatMessages] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [analytics, setAnalytics] = useState({
    pageViews: 0,
    activeUsers: 0,
    avgSessionDuration: 0,
    topPages: []
  });
  const [showPopup, setShowPopup] = useState(false);
  const [newBookingId, setNewBookingId] = useState(null);
  const [chatSessions, setChatSessions] = useState([]);
  const [selectedSession, setSelectedSession] = useState(null);
  const [sessionMessages, setSessionMessages] = useState([]);
  const [cardOrder, setCardOrder] = useState([
    { id: 'pageViews', title: 'Leheküljevaateid', icon: Eye },
    { id: 'activeUsers', title: 'Aktiivsed kasutajad', icon: Users },
    { id: 'avgSession', title: 'Keskmine seanss', icon: Clock },
    { id: 'pendingBookings', title: 'Ootel broneeringud', icon: Calendar }
  ]);
  const [searchQuery, setSearchQuery] = useState('');
  const [autoRefresh, setAutoRefresh] = useState(true);
  const [refreshInterval, setRefreshInterval] = useState(30000);
  const [lastRefresh, setLastRefresh] = useState(new Date());
  const [sortBy, setSortBy] = useState('date'); // 'date', 'status', 'name'
  const [sortOrder, setSortOrder] = useState('desc'); // 'asc', 'desc'
  const [showStats, setShowStats] = useState(true);
  const [notifications, setNotifications] = useState([]);
  const [expandedBookings, setExpandedBookings] = useState(new Set());

  const handleLogin = (e) => {
    e.preventDefault();
    setLoginError('');
    
    if (username === 'Sander' && email === 'sander@nisbel.ee' && password === 'paremkood') {
      setIsAuthenticated(true);
      setUserRole('Admin');
    } else {
      setLoginError('Vale kasutajanimi, e-post või parool');
      setPassword('');
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUserRole('');
    setUsername('');
    setEmail('');
    setPassword('');
  };

  useEffect(() => {
    if (!isAuthenticated) return;
    loadBookings();
    loadAnalytics();
    loadChatSessions();
    
    // Auto-refresh if enabled
    if (autoRefresh) {
      const interval = setInterval(() => {
        checkForNewBookings();
        loadAnalytics();
        loadChatSessions();
        setLastRefresh(new Date());
      }, refreshInterval);
      
      return () => clearInterval(interval);
    }
  }, [autoRefresh, refreshInterval, isAuthenticated]);

  const loadBookings = async () => {
    try {
      setIsLoading(true);
      const params = filter !== 'all' ? { status: filter } : {};
      const response = await axios.get(`${BACKEND_URL}/api/bookings`, { params });
      setBookings(response.data.bookings || []);
    } catch (error) {
      console.error('Failed to load bookings:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const checkForNewBookings = async () => {
    try {
      const response = await axios.get(`${BACKEND_URL}/api/bookings`, { 
        params: { status: 'pending' } 
      });
      
      const pendingBookings = response.data.bookings || [];
      const currentPendingIds = bookings
        .filter(b => b.status === 'pending')
        .map(b => b.id);
      
      // Check if there's a new booking
      const newBooking = pendingBookings.find(b => !currentPendingIds.includes(b.id));
      
      if (newBooking) {
        setNewBookingId(newBooking.id);
        setShowPopup(true);
        setBookings(prev => [newBooking, ...prev]);
        
        // Add notification
        const notification = {
          id: Date.now(),
          type: 'new_booking',
          message: `Uus broneering: ${newBooking.customer_name}`,
          timestamp: new Date(),
          bookingId: newBooking.id
        };
        setNotifications(prev => [notification, ...prev.slice(0, 9)]);
        
        // Play notification sound
        playNotificationSound();
        
        // Browser notification
        if ('Notification' in window && Notification.permission === 'granted') {
          new Notification('Nisbel - Uus broneering', {
            body: `${newBooking.customer_name} - ${newBooking.car_info}`,
            icon: '/nisbel-logo-white-mode.png',
            tag: `booking-${newBooking.id}`
          });
        }
      }
    } catch (error) {
      console.error('Failed to check for new bookings:', error);
    }
  };

  const loadAnalytics = async () => {
    try {
      const response = await axios.get(`${BACKEND_URL}/api/analytics/realtime`);
      const data = response.data;
      
      setAnalytics({
        pageViews: data.pageViews || 0,
        activeUsers: data.activeUsers || 0,
        avgSessionDuration: data.avgSessionDuration || 0,
        topPages: data.topPages || []
      });

      // Log if using mock data
      if (data.mock) {
        console.warn('⚠️ Using mock analytics data. Configure GA credentials to see real data.');
      }
    } catch (error) {
      console.error('Failed to load analytics:', error);
      // Fallback to mock data on error
      setAnalytics({
        pageViews: 0,
        activeUsers: 0,
        avgSessionDuration: 0,
        topPages: []
      });
    }
  };

  const loadChatSessions = async () => {
    try {
      const response = await axios.get(`${BACKEND_URL}/api/chat/sessions?limit=20`);
      setChatSessions(response.data.sessions || []);
    } catch (error) {
      console.error('Failed to load chat sessions:', error);
    }
  };

  const handleSessionClick = async (session) => {
    setSelectedSession(session);
    try {
      const response = await axios.get(`${BACKEND_URL}/api/chat/session/${session.session_id}`);
      setSessionMessages(response.data.messages || []);
    } catch (error) {
      console.error('Failed to load session messages:', error);
      setSessionMessages([]);
    }
  };

  const handleBookingClick = async (booking) => {
    setSelectedBooking(booking);
    
    // Load chat messages for this booking
    try {
      const response = await axios.get(`${BACKEND_URL}/api/chat/booking/${booking.id}`);
      setChatMessages(response.data.messages || []);
    } catch (error) {
      console.error('Failed to load chat messages:', error);
      setChatMessages([]);
    }
  };

  const handleStatusUpdate = async (bookingId, newStatus, approvalNotes = '') => {
    try {
      await axios.patch(`${BACKEND_URL}/api/bookings/${bookingId}/status`, {
        status: newStatus,
        approval_notes: approvalNotes,
        approved_by: 'Admin' // In production, use actual admin user
      });
      
      // Reload bookings
      await loadBookings();
      setSelectedBooking(null);
    } catch (error) {
      console.error('Failed to update booking status:', error);
      alert('Staatuse uuendamine ebaõnnestus');
    }
  };

  const formatDate = (dateString) => {
    if (!dateString) return '';
    const date = new Date(dateString);
    return date.toLocaleDateString('et-EE');
  };

  const formatTime = (timeString) => {
    if (!timeString) return '';
    return timeString.substring(0, 5);
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'pending': return 'bg-red-500/20 text-red-400 border-red-500/50';
      case 'approved': return 'bg-green-500/20 text-green-400 border-green-500/50';
      case 'rejected': return 'bg-gray-500/20 text-gray-400 border-gray-500/50';
      case 'completed': return 'bg-blue-500/20 text-blue-400 border-blue-500/50';
      case 'cancelled': return 'bg-yellow-500/20 text-yellow-400 border-yellow-500/50';
      default: return 'bg-white/10 text-white/60 border-white/20';
    }
  };

  const getStatusLabel = (status) => {
    const labels = {
      pending: 'Ootel',
      approved: 'Kinnitatud',
      rejected: 'Tagasi lükatud',
      completed: 'Lõpetatud',
      cancelled: 'Tühistatud'
    };
    return labels[status] || status;
  };

  const filteredBookings = React.useMemo(() => {
    let result = filter === 'all' ? bookings : bookings.filter(b => b.status === filter);
    
    // Apply search filter
    if (searchQuery.trim()) {
      const query = searchQuery.toLowerCase();
      result = result.filter(b => 
        b.customer_name?.toLowerCase().includes(query) ||
        b.customer_email?.toLowerCase().includes(query) ||
        b.customer_phone?.includes(query) ||
        b.car_info?.toLowerCase().includes(query) ||
        b.service_type?.toLowerCase().includes(query)
      );
    }
    
    // Apply sorting
    result = [...result].sort((a, b) => {
      let comparison = 0;
      
      switch (sortBy) {
        case 'date':
          comparison = new Date(a.created_at) - new Date(b.created_at);
          break;
        case 'status':
          comparison = a.status.localeCompare(b.status);
          break;
        case 'name':
          comparison = a.customer_name.localeCompare(b.customer_name);
          break;
        default:
          comparison = 0;
      }
      
      return sortOrder === 'asc' ? comparison : -comparison;
    });
    
    return result;
  }, [bookings, filter, searchQuery, sortBy, sortOrder]);

  const toggleBookingExpand = (bookingId) => {
    setExpandedBookings(prev => {
      const newSet = new Set(prev);
      if (newSet.has(bookingId)) {
        newSet.delete(bookingId);
      } else {
        newSet.add(bookingId);
      }
      return newSet;
    });
  };

  const exportToCSV = () => {
    const headers = ['ID', 'Klient', 'E-post', 'Telefon', 'Auto', 'Teenus', 'Kuupäev', 'Kellaaeg', 'Staatus'];
    const rows = filteredBookings.map(b => [
      b.id,
      b.customer_name,
      b.customer_email,
      b.customer_phone,
      b.car_info,
      b.service_type,
      formatDate(b.booking_date),
      formatTime(b.booking_time),
      getStatusLabel(b.status)
    ]);
    
    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.map(cell => `"${cell}"`).join(','))
    ].join('\n');
    
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `nisbel-broneeringud-${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  const requestNotificationPermission = () => {
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission();
    }
  };

  const getBookingStats = () => {
    return {
      total: bookings.length,
      pending: bookings.filter(b => b.status === 'pending').length,
      approved: bookings.filter(b => b.status === 'approved').length,
      rejected: bookings.filter(b => b.status === 'rejected').length,
      completed: bookings.filter(b => b.status === 'completed').length,
      today: bookings.filter(b => {
        const today = new Date().toDateString();
        return new Date(b.created_at).toDateString() === today;
      }).length
    };
  };

  const stats = getBookingStats();

  return (
    <div className="min-h-screen bg-[#05070F] p-6">
      {!isAuthenticated ? (
        // Login Form
        <div className="max-w-md mx-auto mt-20">
          <div className="border border-white/10 rounded-2xl p-8 bg-white/[0.02] backdrop-blur-sm">
            <h1 className="text-3xl font-light text-white mb-2 text-center">
              Admin Sisselogimine
            </h1>
            <p className="text-white/60 mb-8 text-center">
              Sisestage oma kasutajaandmed
            </p>

            <form onSubmit={handleLogin} className="space-y-6">
              <div>
                <label htmlFor="username" className="block text-sm font-medium text-white/80 mb-2">
                  Kasutajanimi
                </label>
                <input
                  type="text"
                  id="username"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  className="w-full px-4 py-3 bg-white/5 border border-white/10 rounded-lg text-white placeholder-white/40 focus:outline-none focus:border-[#5ee7df] focus:ring-2 focus:ring-[#5ee7df]/20 transition-all"
                  placeholder="Sisesta kasutajanimi"
                  required
                />
              </div>

              <div>
                <label htmlFor="email" className="block text-sm font-medium text-white/80 mb-2">
                  E-post
                </label>
                <input
                  type="email"
                  id="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full px-4 py-3 bg-white/5 border border-white/10 rounded-lg text-white placeholder-white/40 focus:outline-none focus:border-[#5ee7df] focus:ring-2 focus:ring-[#5ee7df]/20 transition-all"
                  placeholder="Sisesta e-posti aadress"
                  required
                />
              </div>

              <div>
                <label htmlFor="password" className="block text-sm font-medium text-white/80 mb-2">
                  Parool
                </label>
                <input
                  type="password"
                  id="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full px-4 py-3 bg-white/5 border border-white/10 rounded-lg text-white placeholder-white/40 focus:outline-none focus:border-[#5ee7df] focus:ring-2 focus:ring-[#5ee7df]/20 transition-all"
                  placeholder="Sisesta parool"
                  required
                />
              </div>

              {loginError && (
                <div className="bg-red-500/10 border border-red-500/20 rounded-lg p-3 text-red-400 text-sm">
                  {loginError}
                </div>
              )}

              <button
                type="submit"
                className="w-full bg-[#5ee7df] text-[#05070F] py-3 rounded-lg font-semibold hover:bg-[#4dd4cc] transition-colors"
              >
                Logi sisse
              </button>
            </form>
          </div>
        </div>
      ) : (
        // Admin Dashboard
        <div className="max-w-7xl mx-auto">
          {/* Header */}
          <div className="mb-8">
            <div className="flex justify-between items-start mb-6">
              <div>
                <h1 className="text-3xl font-light text-white mb-2">
                  Broneeringute Haldus
                </h1>
                <p className="text-white/60">
                  Haldage kliendibroneering ja jälgige reaalajas analüütikat
                </p>
              </div>
              <div className="flex items-center gap-3">
                {/* Notifications */}
                <div className="relative">
                  <button
                    onClick={() => setNotifications([])}
                    className="p-2 bg-white/5 text-white/80 rounded-lg hover:bg-white/10 transition-colors relative"
                  >
                    <Bell size={20} />
                    {notifications.length > 0 && (
                      <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 rounded-full text-xs flex items-center justify-center">
                        {notifications.length}
                      </span>
                    )}
                  </button>
                </div>

                {/* Auto Refresh Toggle */}
                <button
                  onClick={() => setAutoRefresh(!autoRefresh)}
                  className={`px-3 py-2 rounded-lg text-sm flex items-center gap-2 transition-colors ${
                    autoRefresh
                      ? 'bg-green-500/20 text-green-400 border border-green-500/30'
                      : 'bg-white/5 text-white/60 hover:bg-white/10'
                  }`}
                  title={autoRefresh ? 'Auto-refresh sisse' : 'Auto-refresh välja'}
                >
                  <RefreshCw size={16} className={autoRefresh ? 'animate-spin' : ''} />
                  {autoRefresh && <span className="text-xs">{refreshInterval / 1000}s</span>}
                </button>

                {/* Manual Refresh */}
                <button
                  onClick={() => {
                    loadBookings();
                    loadAnalytics();
                    loadChatSessions();
                    setLastRefresh(new Date());
                  }}
                  className="p-2 bg-white/5 text-white/80 rounded-lg hover:bg-white/10 transition-colors"
                  title="Värskenda käsitsi"
                >
                  <RefreshCw size={20} />
                </button>

                {/* User Info */}
                <div className="text-right">
                  <div className="text-white/80 text-sm">{username}</div>
                  <div className="text-[#5ee7df] text-xs font-semibold">{userRole}</div>
                </div>

                {/* Logout */}
                <button
                  onClick={handleLogout}
                  className="px-4 py-2 bg-white/5 text-white/80 rounded-lg hover:bg-white/10 transition-colors text-sm"
                >
                  Logi välja
                </button>
              </div>
            </div>

            {/* Last Refresh Info */}
            <div className="text-xs text-white/40 flex items-center gap-2">
              <Clock size={12} />
              Viimati uuendatud: {lastRefresh.toLocaleTimeString('et-EE')}
            </div>
          </div>

          {/* Statistics Overview */}
          {showStats && (
            <motion.div
              initial={{ opacity: 0, y: -20 }}
              animate={{ opacity: 1, y: 0 }}
              className="mb-8 grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4"
            >
              <div className="border border-white/10 rounded-lg p-4 bg-white/[0.02]">
                <div className="text-2xl font-light text-white">{stats.total}</div>
                <div className="text-xs text-white/60">Kokku</div>
              </div>
              <div className="border border-yellow-500/30 rounded-lg p-4 bg-yellow-500/5">
                <div className="text-2xl font-light text-yellow-400">{stats.pending}</div>
                <div className="text-xs text-yellow-400/80">Ootel</div>
              </div>
              <div className="border border-green-500/30 rounded-lg p-4 bg-green-500/5">
                <div className="text-2xl font-light text-green-400">{stats.approved}</div>
                <div className="text-xs text-green-400/80">Kinnitatud</div>
              </div>
              <div className="border border-red-500/30 rounded-lg p-4 bg-red-500/5">
                <div className="text-2xl font-light text-red-400">{stats.rejected}</div>
                <div className="text-xs text-red-400/80">Tagasi lükatud</div>
              </div>
              <div className="border border-blue-500/30 rounded-lg p-4 bg-blue-500/5">
                <div className="text-2xl font-light text-blue-400">{stats.completed}</div>
                <div className="text-xs text-blue-400/80">Lõpetatud</div>
              </div>
              <div className="border border-purple-500/30 rounded-lg p-4 bg-purple-500/5">
                <div className="text-2xl font-light text-purple-400">{stats.today}</div>
                <div className="text-xs text-purple-400/80">Täna</div>
              </div>
            </motion.div>
          )}

          {/* Analytics Cards - Draggable */}
          <Reorder.Group
            axis="x"
            values={cardOrder}
            onReorder={setCardOrder}
            className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-8"
          >
            {cardOrder.map((card) => (
              <Reorder.Item
                key={card.id}
                value={card}
                className="border border-white/10 rounded-xl p-6 bg-white/[0.02] backdrop-blur-sm cursor-grab active:cursor-grabbing hover:border-[#5ee7df]/30 transition-colors"
              >
                <div className="flex items-center justify-between mb-2">
                  <card.icon size={20} className="text-[#5ee7df]" />
                  <GripVertical size={16} className="text-white/40" />
                </div>
                <div className="text-2xl font-light text-white mb-1">
                  {card.id === 'pageViews' && analytics.pageViews}
                  {card.id === 'activeUsers' && analytics.activeUsers}
                  {card.id === 'avgSession' && `${Math.floor(analytics.avgSessionDuration / 60)}:${(analytics.avgSessionDuration % 60).toString().padStart(2, '0')}`}
                  {card.id === 'pendingBookings' && bookings.filter(b => b.status === 'pending').length}
                </div>
                <div className="text-sm text-white/60">{card.title}</div>
              </Reorder.Item>
            ))}
          </Reorder.Group>

          {/* Chat Widget Sessions */}
          <div className="mb-8">
            <h2 className="text-xl font-light text-white mb-4 flex items-center gap-2">
              <MessageSquare size={20} className="text-[#5ee7df]" />
              Vestlusajalugu ({chatSessions.length})
            </h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {chatSessions.slice(0, 6).map((session) => (
                <motion.div
                  key={session.session_id}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="border border-white/10 rounded-xl p-4 bg-white/[0.02] backdrop-blur-sm cursor-pointer hover:bg-white/[0.04] transition-colors"
                  onClick={() => handleSessionClick(session)}
                >
                  <div className="flex items-start justify-between mb-2">
                    <div className="flex-1">
                      <div className="text-white/80 text-sm mb-1">
                        Seanss: {session.session_id.substring(0, 8)}...
                      </div>
                      <div className="text-white/60 text-xs">
                        {session.message_count} sõnumit
                      </div>
                    </div>
                    {session.booking_id && (
                      <div className="px-2 py-1 bg-green-500/20 text-green-400 text-xs rounded border border-green-500/30">
                        Broneeritud
                      </div>
                    )}
                  </div>
                  <div className="text-white/50 text-xs line-clamp-2 mb-2">
                    {session.last_user_message || 'Vestlus algas...'}
                  </div>
                  <div className="text-white/40 text-xs">
                    {new Date(session.last_message_at).toLocaleString('et-EE')}
                  </div>
                </motion.div>
              ))}
            </div>
          </div>

          {/* Filters */}
          <div className="mb-6 space-y-4">
            {/* Search and Actions Bar */}
            <div className="flex gap-3 flex-wrap items-center">
              {/* Search */}
              <div className="flex-1 min-w-[300px] relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-white/40" size={18} />
                <input
                  type="text"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder="Otsi kliendi, auto või teenuse järgi..."
                  className="w-full pl-10 pr-4 py-2.5 bg-white/5 border border-white/10 rounded-lg text-white placeholder-white/40 focus:outline-none focus:border-[#5ee7df] focus:ring-2 focus:ring-[#5ee7df]/20 transition-all"
                />
                {searchQuery && (
                  <button
                    onClick={() => setSearchQuery('')}
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-white/40 hover:text-white"
                  >
                    <X size={16} />
                  </button>
                )}
              </div>

              {/* Sort Controls */}
              <select
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value)}
                className="px-4 py-2.5 bg-white/5 border border-white/10 rounded-lg text-white text-sm focus:outline-none focus:border-[#5ee7df] transition-all"
              >
                <option value="date">Sorteeri kuupäeva järgi</option>
                <option value="status">Sorteeri staatuse järgi</option>
                <option value="name">Sorteeri nime järgi</option>
              </select>

              <button
                onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')}
                className="px-3 py-2.5 bg-white/5 border border-white/10 rounded-lg text-white hover:bg-white/10 transition-colors"
                title={sortOrder === 'asc' ? 'Kasvav järjestus' : 'Kahanev järjestus'}
              >
                {sortOrder === 'asc' ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
              </button>

              {/* Export Button */}
              <button
                onClick={exportToCSV}
                className="px-4 py-2.5 bg-[#5ee7df]/10 border border-[#5ee7df]/30 text-[#5ee7df] rounded-lg hover:bg-[#5ee7df]/20 transition-colors flex items-center gap-2 text-sm font-semibold"
              >
                <Download size={18} />
                Ekspordi CSV
              </button>

              {/* Toggle Stats */}
              <button
                onClick={() => setShowStats(!showStats)}
                className="px-3 py-2.5 bg-white/5 border border-white/10 rounded-lg text-white hover:bg-white/10 transition-colors"
                title={showStats ? 'Peida statistika' : 'Näita statistikat'}
              >
                <BarChart3 size={18} />
              </button>
            </div>

            {/* Status Filter Tabs */}
            <div className="flex gap-2 flex-wrap">
              {['all', 'pending', 'approved', 'rejected', 'completed'].map(status => (
                <button
                  key={status}
                  onClick={() => setFilter(status)}
                  className={`px-4 py-2 rounded-lg text-sm transition-colors ${
                    filter === status
                      ? 'bg-[#5ee7df] text-[#05070F] font-semibold'
                      : 'bg-white/5 text-white/60 hover:bg-white/10'
                  }`}
                >
                  {status === 'all' ? `Kõik (${stats.total})` : `${getStatusLabel(status)} (${stats[status] || 0})`}
                </button>
              ))}
            </div>

            {/* Results Count */}
            <div className="text-sm text-white/60">
              Näitan {filteredBookings.length} broneeringut {searchQuery && `"${searchQuery}" päringule`}
            </div>
          </div>

          {/* Bookings List */}
          <div className="space-y-4">
          {isLoading ? (
            <div className="text-center text-white/60 py-12">
              <RefreshCw className="animate-spin mx-auto mb-3" size={32} />
              Laadin...
            </div>
          ) : filteredBookings.length === 0 ? (
            <div className="text-center text-white/60 py-12">
              <AlertCircle className="mx-auto mb-3" size={48} />
              <p className="text-lg mb-2">Broneeringud puuduvad</p>
              {searchQuery && (
                <p className="text-sm">Proovi muuta otsingukriteeriumeid</p>
              )}
            </div>
          ) : (
            filteredBookings.map((booking, index) => {
              const isExpanded = expandedBookings.has(booking.id);
              const isNew = booking.id === newBookingId;
              
              return (
                <motion.div
                  key={booking.id}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: index * 0.05 }}
                  className={`border rounded-xl bg-white/[0.02] backdrop-blur-sm transition-all ${
                    isNew ? 'border-red-500 shadow-lg shadow-red-500/20' : 'border-white/10 hover:border-white/20'
                  }`}
                >
                  {/* Card Header - Always Visible */}
                  <div
                    className="p-6 cursor-pointer"
                    onClick={() => toggleBookingExpand(booking.id)}
                  >
                    <div className="flex items-start justify-between">
                      <div className="flex-1">
                        <div className="flex items-center gap-3 mb-3">
                          <h3 className="text-lg text-white font-light">{booking.customer_name}</h3>
                          <span className={`px-3 py-1 rounded-full text-xs border ${getStatusColor(booking.status)}`}>
                            {getStatusLabel(booking.status)}
                          </span>
                          {isNew && (
                            <span className="px-2 py-1 bg-red-500 text-white text-xs rounded-full animate-pulse">
                              UUS
                            </span>
                          )}
                        </div>

                        {/* Quick Info Grid */}
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-3 text-sm">
                          <div className="flex items-center gap-2 text-white/60">
                            <Car size={14} className="flex-shrink-0" />
                            <span className="truncate">{booking.car_info}</span>
                          </div>
                          <div className="flex items-center gap-2 text-white/60">
                            <Calendar size={14} className="flex-shrink-0" />
                            {formatDate(booking.booking_date)} • {formatTime(booking.booking_time)}
                          </div>
                          <div className="flex items-center gap-2 text-white/60">
                            <Phone size={14} className="flex-shrink-0" />
                            {booking.customer_phone}
                          </div>
                        </div>
                      </div>

                      {/* Expand Button */}
                      <div className="flex items-center gap-3 ml-4">
                        <motion.div
                          animate={{ rotate: isExpanded ? 180 : 0 }}
                          transition={{ duration: 0.3 }}
                        >
                          <ChevronDown size={20} className="text-white/60" />
                        </motion.div>
                      </div>
                    </div>
                  </div>

                  {/* Expanded Details */}
                  <AnimatePresence>
                    {isExpanded && (
                      <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        transition={{ duration: 0.3 }}
                        className="overflow-hidden"
                      >
                        <div className="px-6 pb-6 border-t border-white/10">
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-6">
                            {/* Customer Details */}
                            <div className="space-y-3">
                              <h4 className="text-white/80 text-sm font-semibold uppercase tracking-wider flex items-center gap-2">
                                <User size={14} />
                                Kliendi andmed
                              </h4>
                              <div className="space-y-2 text-sm">
                                <div className="flex items-start gap-2 text-white/60">
                                  <Mail size={14} className="mt-0.5 flex-shrink-0" />
                                  <span className="break-all">{booking.customer_email}</span>
                                </div>
                                <div className="flex items-center gap-2 text-white/60">
                                  <Phone size={14} className="flex-shrink-0" />
                                  <a href={`tel:${booking.customer_phone}`} className="hover:text-[#5ee7df] transition-colors">
                                    {booking.customer_phone}
                                  </a>
                                </div>
                              </div>
                            </div>

                            {/* Booking Details */}
                            <div className="space-y-3">
                              <h4 className="text-white/80 text-sm font-semibold uppercase tracking-wider flex items-center gap-2">
                                <Calendar size={14} />
                                Broneeringu andmed
                              </h4>
                              <div className="space-y-2 text-sm text-white/60">
                                <div>Loodud: {new Date(booking.created_at).toLocaleString('et-EE')}</div>
                                {booking.approved_at && (
                                  <div className="flex items-center gap-2 text-green-400">
                                    <CheckCircle2 size={14} />
                                    Kinnitatud: {new Date(booking.approved_at).toLocaleString('et-EE')}
                                  </div>
                                )}
                                {booking.approved_by && (
                                  <div>Kinnitas: {booking.approved_by}</div>
                                )}
                              </div>
                            </div>
                          </div>

                          {/* Service Description */}
                          <div className="mt-6">
                            <h4 className="text-white/80 text-sm font-semibold uppercase tracking-wider mb-3">
                              Teenuse kirjeldus
                            </h4>
                            <div className="p-4 bg-white/5 border border-white/10 rounded-lg text-white/70 text-sm">
                              {booking.service_type}
                            </div>
                          </div>

                          {/* Action Buttons */}
                          <div className="mt-6 flex gap-3">
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                handleBookingClick(booking);
                              }}
                              className="flex-1 bg-white/10 hover:bg-white/15 text-white py-3 rounded-lg flex items-center justify-center gap-2 transition-colors"
                            >
                              <MessageSquare size={18} />
                              Vaata vestlust
                            </button>

                            {booking.status === 'pending' && (
                              <>
                                <button
                                  onClick={(e) => {
                                    e.stopPropagation();
                                    if (confirm(`Kas kinnitada ${booking.customer_name} broneering?`)) {
                                      handleStatusUpdate(booking.id, 'approved');
                                    }
                                  }}
                                  className="flex-1 bg-green-500 hover:bg-green-600 text-white py-3 rounded-lg flex items-center justify-center gap-2 transition-colors"
                                >
                                  <CheckCircle size={18} />
                                  Kinnita
                                </button>
                                <button
                                  onClick={(e) => {
                                    e.stopPropagation();
                                    const notes = prompt('Tagasilükkamise põhjus:');
                                    if (notes) handleStatusUpdate(booking.id, 'rejected', notes);
                                  }}
                                  className="flex-1 bg-red-500 hover:bg-red-600 text-white py-3 rounded-lg flex items-center justify-center gap-2 transition-colors"
                                >
                                  <XCircle size={18} />
                                  Lükka tagasi
                                </button>
                              </>
                            )}
                          </div>
                        </div>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </motion.div>
              );
            })
          )}
          </div>

        {/* Booking Detail Popup */}
        <AnimatePresence>
          {selectedBooking && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center z-50 p-4"
            onClick={() => setSelectedBooking(null)}
          >
            <motion.div
              initial={{ scale: 0.9, y: 20 }}
              animate={{ scale: 1, y: 0 }}
              exit={{ scale: 0.9, y: 20 }}
              className="bg-[#05070F] border border-white/10 rounded-2xl p-8 max-w-3xl w-full max-h-[90vh] overflow-y-auto"
              onClick={e => e.stopPropagation()}
            >
              <div className="flex items-start justify-between mb-6">
                <div>
                  <h2 className="text-2xl font-light text-white mb-2">
                    Broneeringu detailid
                  </h2>
                  <span className={`px-3 py-1 rounded-full text-xs border ${getStatusColor(selectedBooking.status)}`}>
                    {getStatusLabel(selectedBooking.status)}
                  </span>
                </div>
                <button
                  onClick={() => setSelectedBooking(null)}
                  className="text-white/60 hover:text-white"
                >
                  <X size={24} />
                </button>
              </div>

              {/* Customer & Car Info */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                <div className="space-y-3">
                  <h3 className="text-white/80 text-sm uppercase tracking-wider">Klient</h3>
                  <div className="space-y-2 text-white/60">
                    <div><User size={14} className="inline mr-2" />{selectedBooking.customer_name}</div>
                    <div><Mail size={14} className="inline mr-2" />{selectedBooking.customer_email}</div>
                    <div><Phone size={14} className="inline mr-2" />{selectedBooking.customer_phone}</div>
                  </div>
                </div>

                <div className="space-y-3">
                  <h3 className="text-white/80 text-sm uppercase tracking-wider">Auto</h3>
                  <div className="space-y-2 text-white/60">
                    <div><Car size={14} className="inline mr-2" />{selectedBooking.car_info}</div>
                    <div><Calendar size={14} className="inline mr-2" />{formatDate(selectedBooking.booking_date)} kell {formatTime(selectedBooking.booking_time)}</div>
                  </div>
                </div>
              </div>

              {/* Service Description */}
              <div className="mb-6">
                <h3 className="text-white/80 text-sm uppercase tracking-wider mb-2">Teenus</h3>
                <p className="text-white/60">{selectedBooking.service_type}</p>
              </div>

              {/* Chat Messages */}
              {chatMessages.length > 0 && (
                <div className="mb-6">
                  <h3 className="text-white/80 text-sm uppercase tracking-wider mb-3 flex items-center gap-2">
                    <MessageSquare size={16} />
                    Vestluse ajalugu
                  </h3>
                  <div className="space-y-2 max-h-60 overflow-y-auto bg-white/[0.02] border border-white/10 rounded-lg p-4">
                    {chatMessages.map(msg => (
                      <div
                        key={msg.id}
                        className={`p-3 rounded-lg ${
                          msg.role === 'user' 
                            ? 'bg-[#5ee7df]/10 ml-8' 
                            : 'bg-white/5 mr-8'
                        }`}
                      >
                        <div className="text-xs text-white/40 mb-1">
                          {msg.role === 'user' ? 'Klient' : 'AI Assistent'}
                        </div>
                        <div className="text-white/80 text-sm">{msg.content}</div>
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* Actions */}
              {selectedBooking.status === 'pending' && (
                <div className="flex gap-3">
                  <button
                    onClick={() => handleStatusUpdate(selectedBooking.id, 'approved')}
                    className="flex-1 bg-green-500 hover:bg-green-600 text-white py-3 rounded-lg flex items-center justify-center gap-2 transition-colors"
                  >
                    <CheckCircle size={18} />
                    Kinnita broneering
                  </button>
                  <button
                    onClick={() => {
                      const notes = prompt('Tagasilükkamise põhjus:');
                      if (notes) handleStatusUpdate(selectedBooking.id, 'rejected', notes);
                    }}
                    className="flex-1 bg-red-500 hover:bg-red-600 text-white py-3 rounded-lg flex items-center justify-center gap-2 transition-colors"
                  >
                    <XCircle size={18} />
                    Lükka tagasi
                  </button>
                </div>
              )}
            </motion.div>
          </motion.div>
          )}
        </AnimatePresence>

        {/* Session Chat Modal */}
        <AnimatePresence>
          {selectedSession && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center z-50 p-4"
            onClick={() => setSelectedSession(null)}
          >
            <motion.div
              initial={{ scale: 0.9, y: 20 }}
              animate={{ scale: 1, y: 0 }}
              exit={{ scale: 0.9, y: 20 }}
              className="bg-[#05070F] border border-white/10 rounded-2xl p-8 max-w-3xl w-full max-h-[90vh] overflow-y-auto"
              onClick={e => e.stopPropagation()}
            >
              <div className="flex items-start justify-between mb-6">
                <div>
                  <h2 className="text-2xl font-light text-white mb-2">
                    Vestluse Ajalugu
                  </h2>
                  <div className="text-white/60 text-sm">
                    Seanss: {selectedSession.session_id}
                  </div>
                  <div className="text-white/40 text-xs mt-1">
                    Algas: {new Date(selectedSession.started_at).toLocaleString('et-EE')}
                  </div>
                  {selectedSession.booking_id && (
                    <div className="mt-2 px-3 py-1 bg-green-500/20 text-green-400 text-xs rounded border border-green-500/30 inline-block">
                      Broneeringu ID: {selectedSession.booking_id}
                    </div>
                  )}
                </div>
                <button
                  onClick={() => setSelectedSession(null)}
                  className="text-white/60 hover:text-white"
                >
                  <X size={24} />
                </button>
              </div>

              {/* Session Messages */}
              <div className="space-y-3">
                {sessionMessages.map((msg, index) => (
                  <motion.div
                    key={msg.id}
                    initial={{ opacity: 0, x: msg.role === 'user' ? 20 : -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: index * 0.05 }}
                    className={`p-4 rounded-lg ${
                      msg.role === 'user' 
                        ? 'bg-[#5ee7df]/10 ml-12 border border-[#5ee7df]/20' 
                        : msg.role === 'assistant'
                        ? 'bg-white/5 mr-12 border border-white/10'
                        : 'bg-yellow-500/10 border border-yellow-500/20'
                    }`}
                  >
                    <div className="flex items-center justify-between mb-2">
                      <div className="text-xs font-semibold uppercase tracking-wider">
                        {msg.role === 'user' && <span className="text-[#5ee7df]">Kasutaja</span>}
                        {msg.role === 'assistant' && <span className="text-white/60">AI Assistent</span>}
                        {msg.role === 'system' && <span className="text-yellow-500">Süsteem</span>}
                      </div>
                      <div className="text-xs text-white/40">
                        {new Date(msg.created_at).toLocaleTimeString('et-EE')}
                      </div>
                    </div>
                    <div className="text-white/80 text-sm leading-relaxed whitespace-pre-wrap">
                      {msg.content}
                    </div>
                    {msg.extracted_data && (
                      <div className="mt-2 p-2 bg-black/20 rounded text-xs text-white/50">
                        <strong>Ekstraktitud andmed:</strong>
                        <pre className="mt-1 overflow-x-auto">{JSON.stringify(JSON.parse(msg.extracted_data), null, 2)}</pre>
                      </div>
                    )}
                  </motion.div>
                ))}
              </div>

              {sessionMessages.length === 0 && (
                <div className="text-center text-white/40 py-12">
                  Sõnumeid ei leitud
                </div>
              )}
            </motion.div>
          </motion.div>
          )}
        </AnimatePresence>

        {/* New Booking Notification Popup */}
        <AnimatePresence>
          {showPopup && (
          <motion.div
            initial={{ opacity: 0, scale: 0.8, y: 50 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.8, y: 50 }}
            className="fixed bottom-6 right-6 bg-gradient-to-r from-red-500 to-orange-500 text-white p-6 rounded-xl shadow-2xl max-w-sm z-50"
          >
            <div className="flex items-start justify-between mb-3">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-white/20 rounded-full flex items-center justify-center animate-pulse">
                  <Calendar size={20} />
                </div>
                <div>
                  <h3 className="font-semibold">Uus broneering!</h3>
                  <p className="text-sm opacity-90">Uus klient ootab kinnitust</p>
                </div>
              </div>
              <button
                onClick={() => setShowPopup(false)}
                className="text-white/80 hover:text-white"
              >
                <X size={18} />
              </button>
            </div>
            <button
              onClick={() => {
                setShowPopup(false);
                const booking = bookings.find(b => b.id === newBookingId);
                if (booking) handleBookingClick(booking);
              }}
              className="w-full bg-white text-red-500 py-2 rounded-lg font-semibold hover:bg-gray-100 transition-colors"
            >
              Vaata broneeringut
            </button>
          </motion.div>
          )}
        </AnimatePresence>
      </div>
      )}
    </div>
  );
}

export default AdminDashboard;
