import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, Send, X, Phone, Calendar, Bot, User } from 'lucide-react';
import { Button } from './button';
import { Input } from './input';
import { Textarea } from './textarea';
import { Label } from './label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from './select';
import { motion, AnimatePresence } from 'framer-motion';
import OpenAI from 'openai';
import emailjs from '@emailjs/browser';

// Initialize OpenAI
const openai = new OpenAI({
  apiKey: import.meta.env.VITE_OPENAI_API_KEY,
  dangerouslyAllowBrowser: true
});

// System prompt for Nisbel Autostuudio
const systemPrompt = `Sa oled Nisbel Autostuudio AI assistent Tallinnas. Sa oled sõbralik, professionaalne ja abivalmis.

Teenused mida pakume:
- Autodiagnostika (OBD/CAN analüüs)
- Rehvitööd (vahetus, tasakaalustamine, hooldus)
- Mootoritööd (remont, hooldus, ajastus)
- Elektriremont (juhtplokid, sensorid, juhtmestik)
- Pidurid ja veermik (remont, hooldus)
- Detailing (puhastus, kaitse, poleerimine)

Kontaktinfo:
- Telefon: +372 5684 6555
- WhatsApp: https://wa.me/37256846555
- Aadress: Pärnu mnt 393, Tallinn

Reeglid:
- Räägi ainult eesti keeles
- Ole lühike ja konkreetne
- Kui klient küsib hinda, ütle et saatke päring vormi kaudu
- Kui klient tahab broneerida, paku "Broneeri aeg" nuppu
- Kui ei tea vastust, ütle et võtame ühendust telefoni teel

Vasta kliendi küsimustele professionaalselt ja paku järgmisi samme.`;

// Service knowledge base
const SERVICE_KNOWLEDGE = [
  {
    keywords: ['õli', 'vahetus', 'mootoriõli'],
    response: 'Mootoriõli vahetus on oluline hooldus, mis tagab mootori pikaealisuse. Hind sõltub auto mudelist ja õli tüübist.'
  },
  {
    keywords: ['pidur', 'pidurid', 'piduriklotsid'],
    response: 'Pidurite remont on kriitiline ohutuse tagamiseks. Teostame nii ketas- kui trummelpidurite remonti.'
  },
  {
    keywords: ['veermik', 'amortisaator', 'vedrustus'],
    response: 'Veermiku remont parandab auto juhitavust ja sõidumugavust. Kontrollime ja remontime amortisaatoreid, stabilisaatoreid ja liigendeid.'
  },
  {
    keywords: ['diagnostika', 'diagnoos', 'kontroll'],
    response: 'Autodiagnostika aitab tuvastada probleeme enne nende süvenemist. Kasutame professionaalset OBD/CAN seadmeid.'
  },
  {
    keywords: ['rehv', 'rehvid', 'vahetus'],
    response: 'Rehvitööd hõlmavad vahetust, tasakaalustamist ja hooldust. Aitame valida õiged rehvid Teie auto jaoks.'
  }
];

const APPOINTMENT_KEYWORDS = ['broneeri', 'aeg', 'kokku', 'leppida', 'tulla', 'külastada', 'remont', 'hooldus'];
const PHONE_NUMBER = '+372 5684 6555';

const createMessage = (type, content) => ({
  id: `${type}-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
  type,
  content,
  timestamp: new Date()
});

const shouldSuggestAppointment = (text = '') => {
  const normalized = text.toLowerCase();
  return APPOINTMENT_KEYWORDS.some(keyword => normalized.includes(keyword));
};

const generateFallbackResponse = (userInput, reason = 'fallback') => {
  const normalized = userInput.toLowerCase();
  const matchedService = SERVICE_KNOWLEDGE.find(service =>
    service.keywords.some(keyword => normalized.includes(keyword))
  );

  let intro;
  if (reason === 'error') {
    intro = 'Vabandame, AI-teenus on hetkel ülekoormatud. Kasutan vastamiseks kohalikku teadmistebaasi.';
  } else if (reason === 'no-key') {
    intro = 'AI-teenuse võti pole seadistatud. Kasutan vastamiseks kohalikku teadmistebaasi.';
  } else {
    intro = 'AI-teenus pole hetkel saadaval. Kasutan vastamiseks kohalikku teadmistebaasi.';
  }

  const responseParts = [
    intro,
    matchedService
      ? matchedService.response
      : 'Teostame Tallinnas diagnostikat, rehvitood, piduri- ja veermikuremonti, elektritood ning salongi ja kere detailingu.'
  ];

  if (
    normalized.includes('hind') ||
    normalized.includes('maks') ||
    normalized.includes('palju') ||
    normalized.includes('kulu')
  ) {
    responseParts.push(
      'Hinnavahemikud: diagnostika 50-150 eura, rehvitood 40-80 eura, olivahetus 60-120 eura, piduritood 150-400 eura, veermik 200-600 eura ja elektritood 100-500 eura.'
    );
  }

  if (shouldSuggestAppointment(userInput)) {
    responseParts.push(
      `Broneeringu tegemiseks kirjuta siia oma nimi, telefoni number ja sobiv aeg voi helista otse numbril ${PHONE_NUMBER}.`
    );
  } else {
    responseParts.push(
      `Anna mulle auto mark/mudel ning symptom (nt helid, veateated). Valmistame hinnangu ette voi saad kiire vastuse telefonilt ${PHONE_NUMBER}.`
    );
  }

  return responseParts.join('\n\n');
};

const ChatWidget = () => {
  const apiKey = import.meta.env.VITE_OPENAI_API_KEY;
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState(() => [
    createMessage(
      'bot',
      'Tere! Ma olen Nisbel Autostuudio AI assistent. Kuidas saan teid aidata? Võin vastata teenuste kohta, anda hinnavahemikke või aidata aja broneerida.'
    )
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [showAppointmentForm, setShowAppointmentForm] = useState(false);
  const [appointmentData, setAppointmentData] = useState({
    name: '',
    phone: '',
    service: '',
    preferredDate: '',
    message: ''
  });
  const [isBooking, setIsBooking] = useState(false);
  const [bookingMessage, setBookingMessage] = useState('');
  const messagesEndRef = useRef(null);

  const triggerAppointmentIfNeeded = (text = '') => {
    if (shouldSuggestAppointment(text)) {
      setTimeout(() => setShowAppointmentForm(true), 1000);
    }
  };

  const pushBotMessage = (content, options = {}) => {
    const { triggerText, skipAppointmentCheck = false } = options;
    setMessages(prev => [...prev, createMessage('bot', content)]);
    if (!skipAppointmentCheck) {
      const source = triggerText ?? content ?? '';
      triggerAppointmentIfNeeded(source);
    }
  };

  const respondWithFallback = (userText, reason = 'fallback') => {
    const fallbackMessage = generateFallbackResponse(userText, reason);
    pushBotMessage(fallbackMessage, { triggerText: userText });
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSendMessage = async () => {
    const trimmedMessage = inputMessage.trim();
    if (!trimmedMessage) return;

    const userMessage = createMessage('user', trimmedMessage);

    setMessages(prev => [...prev, userMessage]);
    setInputMessage('');
    setIsTyping(true);

    if (!apiKey) {
      respondWithFallback(trimmedMessage, 'no-key');
      setIsTyping(false);
      return;
    }

    try {
      const completion = await openai.chat.completions.create({
        model: 'gpt-3.5-turbo',
        messages: [
          { role: 'system', content: systemPrompt },
          ...messages.slice(1).map(msg => ({
            role: msg.type === 'user' ? 'user' : 'assistant',
            content: msg.content
          })),
          { role: 'user', content: trimmedMessage }
        ],
        max_tokens: 500,
        temperature: 0.7
      });

      const botMessage = completion.choices[0].message.content.trim();
      pushBotMessage(botMessage);
    } catch (error) {
      console.error('OpenAI Error:', error);
      respondWithFallback(trimmedMessage, 'error');
    } finally {
      setIsTyping(false);
    }
  };

  const handleAppointmentSubmit = async (e) => {
    e.preventDefault();
    setIsBooking(true);
    setBookingMessage('');

    try {
      await emailjs.send(
        import.meta.env.VITE_EMAILJS_SERVICE_ID,
        import.meta.env.VITE_EMAILJS_TEMPLATE_ID,
        {
          from_name: appointmentData.name,
          phone: appointmentData.phone,
          service: appointmentData.service,
          preferred_date: appointmentData.preferredDate,
          message: appointmentData.message,
          to_email: 'write-us@nisbel.ee',
          source: 'AI Chat Widget'
        },
        import.meta.env.VITE_EMAILJS_PUBLIC_KEY
      );

      setBookingMessage('Aeg edukalt broneeritud! Võtame ühendust 24h jooksul kinnitamiseks.');
      setAppointmentData({
        name: '',
        phone: '',
        service: '',
        preferredDate: '',
        message: ''
      });
      setShowAppointmentForm(false);

      pushBotMessage('Täname! Teie broneering on saadetud. Võtame ühendust 24 tunni jooksul.', {
        skipAppointmentCheck: true
      });

    } catch (error) {
      console.error('Booking error:', error);
      setBookingMessage('Viga broneerimisel. Palun proovige uuesti või helistage.');
    } finally {
      setIsBooking(false);
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  return (
    <>
      {/* Chat Toggle Button */}
      <motion.div
        className="fixed bottom-4 right-4 z-50"
        initial={{ scale: 0 }}
        animate={{ scale: 1 }}
        transition={{ duration: 0.3 }}
      >
        <Button
          onClick={() => setIsOpen(!isOpen)}
          size="icon"
          className="rounded-full bg-[#004E92] hover:bg-[#00366A] shadow-lg shadow-[#004E92]/30 hover:shadow-xl h-14 w-14"
          aria-label="Ava AI chat"
        >
          <motion.div
            animate={{ rotate: isOpen ? 45 : 0 }}
            transition={{ duration: 0.3 }}
          >
            {isOpen ? <X className="h-6 w-6" /> : <MessageCircle className="h-6 w-6" />}
          </motion.div>
        </Button>
      </motion.div>

      {/* Chat Window */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, scale: 0.8, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.8, y: 20 }}
            transition={{ duration: 0.3 }}
            className="fixed bottom-20 right-4 z-50 w-80 md:w-96 h-96 bg-white dark:bg-slate-900 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 overflow-hidden"
            data-test-chat-panel="open"
          >
            {/* Chat Header */}
            <div className="bg-[#004E92] text-white p-4 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Bot className="h-5 w-5" />
                <span className="font-semibold">Nisbel AI Assist</span>
              </div>
              <Button
                onClick={() => setIsOpen(false)}
                size="icon"
                variant="ghost"
                className="text-white hover:bg-white/20 h-8 w-8"
              >
                <X className="h-4 w-4" />
              </Button>
            </div>

            {/* Messages Container */}
            <div className="flex-1 overflow-y-auto p-4 space-y-3 h-64">
              {messages.map((message) => (
                <motion.div
                  key={message.id}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className={`flex ${message.type === 'user' ? 'justify-end' : 'justify-start'}`}
                  data-test-chat-message={message.type}
                >
                  <div className={`flex gap-2 max-w-[80%] ${message.type === 'user' ? 'flex-row-reverse' : ''}`}>
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center ${
                      message.type === 'user'
                        ? 'bg-[#004E92] text-white'
                        : 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400'
                    }`}>
                      {message.type === 'user' ? <User className="h-4 w-4" /> : <Bot className="h-4 w-4" />}
                    </div>
                    <div className={`rounded-2xl px-3 py-2 ${
                      message.type === 'user'
                        ? 'bg-[#004E92] text-white'
                        : 'bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-slate-100'
                    }`}>
                      <p className="text-sm whitespace-pre-wrap">{message.content}</p>
                      <p className="text-xs opacity-70 mt-1">
                        {message.timestamp.toLocaleTimeString('et-EE', {
                          hour: '2-digit',
                          minute: '2-digit'
                        })}
                      </p>
                    </div>
                  </div>
                </motion.div>
              ))}

              {/* Typing Indicator */}
              {isTyping && (
                <motion.div
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  className="flex justify-start"
                >
                  <div className="flex gap-2 max-w-[80%]">
                    <div className="w-8 h-8 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center">
                      <Bot className="h-4 w-4" />
                    </div>
                    <div className="bg-slate-100 dark:bg-slate-800 rounded-2xl px-3 py-2">
                      <div className="flex space-x-1">
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
                        <div className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                      </div>
                    </div>
                  </div>
                </motion.div>
              )}

              {/* Appointment Form */}
              {showAppointmentForm && (
                <motion.div
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="bg-blue-50 dark:bg-slate-800 rounded-2xl p-4"
                  data-test-appointment-form
                >
                  <div className="flex items-center gap-2 mb-3">
                    <Calendar className="h-4 w-4 text-[#004E92]" />
                    <span className="font-semibold text-slate-900 dark:text-slate-100">Broneeri aeg</span>
                  </div>

                  {bookingMessage && (
                    <div className={`mb-3 p-2 rounded-lg text-sm ${
                      bookingMessage.includes('edukalt')
                        ? 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200'
                        : 'bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200'
                    }`}>
                      {bookingMessage}
                    </div>
                  )}

                  <form onSubmit={handleAppointmentSubmit} className="space-y-3" data-test-appointment-form-fields>
                    <div>
                      <Label htmlFor="name" className="text-xs">Nimi *</Label>
                      <Input
                        id="name"
                        value={appointmentData.name}
                        onChange={(e) => setAppointmentData({...appointmentData, name: e.target.value})}
                        placeholder="Teie nimi"
                        required
                        className="h-8 text-sm"
                      />
                    </div>
                    <div>
                      <Label htmlFor="phone" className="text-xs">Telefon *</Label>
                      <Input
                        id="phone"
                        value={appointmentData.phone}
                        onChange={(e) => setAppointmentData({...appointmentData, phone: e.target.value})}
                        placeholder="+372 5..."
                        required
                        className="h-8 text-sm"
                      />
                    </div>
                    <div>
                      <Label htmlFor="service" className="text-xs">Teenuse tüüp *</Label>
                      <Select value={appointmentData.service} onValueChange={(value) => setAppointmentData({...appointmentData, service: value})}>
                        <SelectTrigger className="h-8 text-sm">
                          <SelectValue placeholder="Valige teenus" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="Diagnostika">Diagnostika</SelectItem>
                          <SelectItem value="Rehvitööd">Rehvitööd</SelectItem>
                          <SelectItem value="Mootoritööd">Mootoritööd</SelectItem>
                          <SelectItem value="Elektriremont">Elektriremont</SelectItem>
                          <SelectItem value="Pidurid">Pidurid</SelectItem>
                          <SelectItem value="Veermiku remont">Veermiku remont</SelectItem>
                          <SelectItem value="Detailing">Detailing</SelectItem>
                          <SelectItem value="Muu">Muu</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    <div>
                      <Label htmlFor="preferredDate" className="text-xs">Eelistatud aeg</Label>
                      <Input
                        id="preferredDate"
                        type="datetime-local"
                        value={appointmentData.preferredDate}
                        onChange={(e) => setAppointmentData({...appointmentData, preferredDate: e.target.value})}
                        className="h-8 text-sm"
                      />
                    </div>
                    <div>
                      <Label htmlFor="message" className="text-xs">Lisainfo</Label>
                      <Textarea
                        id="message"
                        value={appointmentData.message}
                        onChange={(e) => setAppointmentData({...appointmentData, message: e.target.value})}
                        placeholder="Kirjutage lühidalt oma soovist..."
                        rows={2}
                        className="text-sm resize-none"
                      />
                    </div>
                    <Button
                      type="submit"
                      size="sm"
                      disabled={isBooking}
                      className="w-full bg-[#004E92] hover:bg-[#00366A] h-8 text-sm"
                    >
                      {isBooking ? 'Broneerin...' : 'Broneeri aeg'}
                    </Button>
                  </form>
                </motion.div>
              )}

              <div ref={messagesEndRef} />
            </div>

            {/* Input Area */}
            {!showAppointmentForm && (
              <div className="border-t border-slate-200 dark:border-slate-700 p-3">
                <div className="flex gap-2">
                  <Input
                    value={inputMessage}
                    onChange={(e) => setInputMessage(e.target.value)}
                    onKeyPress={handleKeyPress}
                    placeholder="Kirjutage oma küsimus..."
                    className="flex-1 h-9 text-sm"
                    disabled={isTyping}
                    data-test-chat-input
                  />
                  <Button
                    onClick={handleSendMessage}
                    size="icon"
                    disabled={!inputMessage.trim() || isTyping}
                    className="bg-[#004E92] hover:bg-[#00366A] h-9 w-9"
                    data-test-chat-send
                  >
                    <Send className="h-4 w-4" />
                  </Button>
                </div>
                <div className="flex justify-between items-center mt-2 text-xs text-slate-500">
                  <span>Vajutage Enter saatmiseks</span>
                  <button
                    onClick={() => setShowAppointmentForm(true)}
                    className="text-[#004E92] hover:underline flex items-center gap-1"
                    data-test-chat-open-booking
                  >
                    <Calendar className="h-3 w-3" />
                    Broneeri aeg
                  </button>
                </div>
              </div>
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default ChatWidget;
