// Google Analytics tracking utilities

export const trackEvent = (eventName, parameters = {}) => {
  if (typeof window !== "undefined" && window.gtag) {
    window.gtag("event", eventName, parameters);
  } else {
    console.log("GA4 Event:", eventName, parameters);
  }
};

/**
 * Fetch real-time Google Analytics data
 */
const GA_API_ENDPOINT = 'https://www.googleapis.com/analytics/v3/data/realtime';

export async function fetchRealtimeAnalytics(measurementId, apiKey) {
  try {
    const params = new URLSearchParams({
      ids: `ga:${measurementId}`,
      metrics: 'rt:activeUsers,rt:pageviews,rt:avgSessionDuration',
      dimensions: 'rt:pagePath',
      key: apiKey
    });

    const response = await fetch(`${GA_API_ENDPOINT}?${params}`);
    
    if (!response.ok) {
      throw new Error(`GA API error: ${response.status}`);
    }

    const data = await response.json();
    
    return {
      activeUsers: data.totalsForAllResults?.['rt:activeUsers'] || 0,
      pageViews: data.totalsForAllResults?.['rt:pageviews'] || 0,
      avgSessionDuration: data.totalsForAllResults?.['rt:avgSessionDuration'] || 0,
      topPages: data.rows?.map(row => ({
        page: row[0],
        views: parseInt(row[1]) || 0
      })) || []
    };
  } catch (error) {
    console.error('Failed to fetch GA realtime data:', error);
    return {
      activeUsers: 0,
      pageViews: 0,
      avgSessionDuration: 0,
      topPages: []
    };
  }
}

/**
 * Track custom booking event
 */
export function trackBookingEvent(bookingId, customerEmail, serviceType) {
  if (window.gtag) {
    window.gtag('event', 'booking_submitted', {
      event_category: 'Bookings',
      event_label: serviceType,
      booking_id: bookingId,
      customer_email: customerEmail
    });
  }
}

/**
 * Track chat widget interaction
 */
export function trackChatEvent(action, label) {
  if (window.gtag) {
    window.gtag('event', action, {
      event_category: 'Chat Widget',
      event_label: label
    });
  }
}


