import React from 'react';
import {
  BlogPostLayout,
  BlogSection,
  BlogParagraph,
  BlogStrong,
} from '../../src/components/BlogPostLayout';

export default function BlogHammasrihmaKomplekt() {
  return (
    <BlogPostLayout
      title="Hammasrihma komplekt – miks ainult rihma vahetamine on halb plaan?"
      description="Selgitame, mis on hammasrihma komplekt, miks sinna kuuluvad pingutid ja rullikud ning miks ainult rihma vahetamine on riskantne kokkuhoid."
      category="Mootorihooldus"
      publishedAt="2024-11-15"
      readTime="5 min"
      slug="hammasrihma-komplekt"
      featuredImage="/autohooldus-tallinnas-premium.webp"
    >
      <TableOfContents
            items={[
              { id: "sisaldab", title: "Mida komplekt sisaldab?" },
              { id: "kriitilised", title: "Miks pingutid ja rullikud on kriitilised?" },
              { id: "uus-risk", title: "Vana rullik uue rihmaga = uus risk" },
              { id: "kokkuhoid", title: "Kokkuhoid täna, topeltkulu homme" },
              { id: "kokkuvote", title: "Kokkuvõte" },
            ]}
          />

          <HighlightBox title="Oluline teada">
            <Paragraph>
              Tihti küsitakse: „Kas ei saa ainult rihma ära vahetada, siis on odavam?" Tehniline vastus: saab, aga ei ole mõistlik. <Strong>Hammasrihma komplekt</Strong> sisaldab rihma, pinguteid ja rullikuid põhjusega.
            </Paragraph>
          </HighlightBox>

          <Heading as="h2" id="sisaldab">Mida komplekt sisaldab?</Heading>
          <Paragraph>
            Sõltuvalt mootorist sisaldab komplekt tavaliselt <Strong>hammasrihma</Strong>, <Strong>pingutusrullikuid</Strong>, <Strong>juhtrullikuid</Strong> ja tihti ka kinnitusi ning polte.
          </Paragraph>

          <Divider />

          <Heading as="h2" id="kriitilised">Miks pingutid ja rullikud on kriitilised?</Heading>
          <Paragraph>
            Kui vana rullik või pinguti jookseb kinni, hakkab rihm <Strong>üle libisema või hammaste pealt maha hüppama</Strong>. Tulemus on sama, mis rihma purunemisel – <Strong>mootorikahjustus</Strong>.
          </Paragraph>

          <Callout type="warning" title="Hoiatus!">
            Vana rullik uue rihmaga võib põhjustada ootamatuid probleeme ja kallist remonti.
          </Callout>

          <Divider />

          <Heading as="h2" id="uus-risk">Vana rullik uue rihmaga = uus risk</Heading>
          <Paragraph>
            Uus rihm töötab pingul ja elastne. Vana rullik võib olla laagriga, mis on kuivanud või roostes. Mõne tuhande kilomeetri pärast hakkab ta häälitsema või kinni jooksma.
          </Paragraph>

          <Callout type="technical" title="Tehniline detail">
            Rullikute laagrid vajavad regulaarset hooldust ja vahetust koos rihmaga.
          </Callout>

          <Divider />

          <Heading as="h2" id="kokkuhoid">Kokkuhoid täna, topeltkulu homme</Heading>
          <Paragraph>
            Kui vahetad ainult rihma ja hiljem sureb rullik, tuleb uuesti kogu esiosa lahti võtta, panna uus komplekt ja maksta uuesti tööraha. Ehk: kaks korda tööd, üks „kokkuhoid".
          </Paragraph>

          <Callout type="tip" title="Pro nõuanne">
            Investeeri kohe õigesse komplekti – säästad aega ja raha pikemas perspektiivis.
          </Callout>

          <Divider />

          <Heading as="h2" id="kokkuvote">Kokkuvõte: hammasrihma töö tehakse korraga ja korralikult</Heading>
          <Quote>
            Hammasrihma komplekti vahetus tähendab kogu süsteemi korrastamist – mitte ainult ühe jubina väljavahetamist. See on ainus mõistlik viis vähendada riski, et väike rullik viib kaasa suure mootoriremondi.
          </Quote>

          <CTAButton href="/#contact" primary>
            <Wrench size={20} />
            Broneeri hammasrihma vahetus
          </CTAButton>
    </BlogPostLayout>
  );
}
