import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Calendar, Clock, Car, User, Mail, Phone, FileText, CheckCircle, XCircle } from 'lucide-react';
import axios from 'axios';

const BACKEND_URL = import.meta.env.VITE_API_URL || 'http://localhost:3001';

function BookingForm() {
  const [formData, setFormData] = useState({
    customer_name: '',
    customer_email: '',
    customer_phone: '',
    car_make: '',
    car_model: '',
    car_year: '',
    car_registration: '',
    car_mileage: '',
    service_type: '',
    service_description: '',
    booking_date: '',
    booking_time: ''
  });

  const [availableSlots, setAvailableSlots] = useState([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState(null);
  const [errors, setErrors] = useState({});

  const serviceTypes = [
    'Diagnostika',
    'Mootorihooldus',
    'Pidurite hooldus',
    'Veermiku hooldus',
    'Elektritööd',
    'Kliimaseadme hooldus',
    'Õlivahetus',
    'Üldhooldus',
    'Muu teenus'
  ];

  // Generate time slots (every hour from 08:00 to 18:00)
  const generateTimeSlots = () => {
    const slots = [];
    for (let hour = 8; hour <= 18; hour++) {
      const timeString = `${hour.toString().padStart(2, '0')}:00:00`;
      slots.push(timeString);
    }
    return slots;
  };

  // Fetch available time slots when date changes
  useEffect(() => {
    if (formData.booking_date) {
      // Try to fetch from backend, fallback to generated slots
      fetchAvailableSlots(formData.booking_date);
    } else {
      setAvailableSlots([]);
    }
  }, [formData.booking_date]);

  const fetchAvailableSlots = async (date) => {
    try {
      const response = await axios.get(`${BACKEND_URL}/api/bookings/availability/${date}`);
      setAvailableSlots(response.data.available_slots || generateTimeSlots());
    } catch (error) {
      console.warn('Backend not available, using default time slots');
      // Fallback to generated time slots if backend is not available
      setAvailableSlots(generateTimeSlots());
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    // Clear error for this field
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: '' }));
    }
  };

  const validateForm = () => {
    const newErrors = {};
    
    if (!formData.customer_name.trim()) newErrors.customer_name = 'Nimi on kohustuslik';
    if (!formData.customer_email.trim()) newErrors.customer_email = 'E-post on kohustuslik';
    if (!formData.customer_phone.trim()) newErrors.customer_phone = 'Telefon on kohustuslik';
    if (!formData.car_make.trim()) newErrors.car_make = 'Auto mark on kohustuslik';
    if (!formData.car_model.trim()) newErrors.car_model = 'Auto mudel on kohustuslik';
    if (!formData.car_year) newErrors.car_year = 'Auto aasta on kohustuslik';
    if (!formData.car_registration.trim()) newErrors.car_registration = 'Registreerimisnumber on kohustuslik';
    if (!formData.service_type) newErrors.service_type = 'Teenuse tüüp on kohustuslik';
    if (!formData.booking_date) newErrors.booking_date = 'Kuupäev on kohustuslik';
    if (!formData.booking_time) newErrors.booking_time = 'Aeg on kohustuslik';
    
    // Email validation
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (formData.customer_email && !emailRegex.test(formData.customer_email)) {
      newErrors.customer_email = 'Vigane e-posti aadress';
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!validateForm()) {
      setSubmitStatus({ type: 'error', message: 'Palun täida kõik kohustuslikud väljad' });
      return;
    }
    
    setIsSubmitting(true);
    setSubmitStatus(null);
    
    try {
      await axios.post(`${BACKEND_URL}/api/bookings`, formData);
      
      setSubmitStatus({ 
        type: 'success', 
        message: 'Broneering on edukalt esitatud! Võtame teiega peagi ühendust kinnitamiseks.' 
      });
      
      // Reset form
      setFormData({
        customer_name: '',
        customer_email: '',
        customer_phone: '',
        car_make: '',
        car_model: '',
        car_year: '',
        car_registration: '',
        car_mileage: '',
        service_type: '',
        service_description: '',
        booking_date: '',
        booking_time: ''
      });
    } catch (error) {
      console.error('Booking submission error:', error);
      setSubmitStatus({ 
        type: 'error', 
        message: 'Broneeringu esitamine ebaõnnestus. Palun proovige hiljem uuesti.' 
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  // Get minimum date (today)
  const getMinDate = () => {
    const today = new Date();
    return today.toISOString().split('T')[0];
  };

  return (
    <div className="min-h-screen bg-[#05070F] py-20 px-4">
      <div className="max-w-3xl mx-auto">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
        >
          <h1 className="text-4xl font-light text-white mb-4 text-center">
            Broneeri Aeg
          </h1>
          <p className="text-white/60 text-center mb-12">
            Täida vorm ja me võtame teiega ühendust broneeringu kinnitamiseks
          </p>

          <form onSubmit={handleSubmit} className="space-y-8">
            {/* Customer Information */}
            <div className="border border-white/10 rounded-2xl p-6 bg-white/[0.02] backdrop-blur-sm">
              <h2 className="text-xl font-light text-white mb-6 flex items-center gap-2">
                <User size={20} className="text-[#5ee7df]" />
                Kliendi andmed
              </h2>
              
              <div className="space-y-4">
                <div>
                  <label className="block text-sm text-white/80 mb-2">Nimi *</label>
                  <input
                    type="text"
                    name="customer_name"
                    value={formData.customer_name}
                    onChange={handleChange}
                    className={`w-full bg-white/5 border ${errors.customer_name ? 'border-red-500' : 'border-white/10'} rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#5ee7df]`}
                    placeholder="Teie nimi"
                  />
                  {errors.customer_name && <p className="text-red-500 text-sm mt-1">{errors.customer_name}</p>}
                </div>

                <div>
                  <label className="block text-sm text-white/80 mb-2">E-post *</label>
                  <input
                    type="email"
                    name="customer_email"
                    value={formData.customer_email}
                    onChange={handleChange}
                    className={`w-full bg-white/5 border ${errors.customer_email ? 'border-red-500' : 'border-white/10'} rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#5ee7df]`}
                    placeholder="teie@email.ee"
                  />
                  {errors.customer_email && <p className="text-red-500 text-sm mt-1">{errors.customer_email}</p>}
                </div>

                <div>
                  <label className="block text-sm text-white/80 mb-2">Telefon *</label>
                  <input
                    type="tel"
                    name="customer_phone"
                    value={formData.customer_phone}
                    onChange={handleChange}
                    className={`w-full bg-white/5 border ${errors.customer_phone ? 'border-red-500' : 'border-white/10'} rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#5ee7df]`}
                    placeholder="+372 5XXX XXXX"
                  />
                  {errors.customer_phone && <p className="text-red-500 text-sm mt-1">{errors.customer_phone}</p>}
                </div>
              </div>
            </div>

            {/* Car Information */}
            <div className="border border-white/10 rounded-2xl p-6 bg-white/[0.02] backdrop-blur-sm">
              <h2 className="text-xl font-light text-white mb-6 flex items-center gap-2">
                <Car size={20} className="text-[#5ee7df]" />
                Auto andmed
              </h2>
              
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm text-white/80 mb-2">Mark *</label>
                  <input
                    type="text"
                    name="car_make"
                    value={formData.car_make}
                    onChange={handleChange}
                    className={`w-full bg-white/5 border ${errors.car_make ? 'border-red-500' : 'border-white/10'} rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#5ee7df]`}
                    placeholder="nt. BMW"
                  />
                  {errors.car_make && <p className="text-red-500 text-sm mt-1">{errors.car_make}</p>}
                </div>

                <div>
                  <label className="block text-sm text-white/80 mb-2">Mudel *</label>
                  <input
                    type="text"
                    name="car_model"
                    value={formData.car_model}
                    onChange={handleChange}
                    className={`w-full bg-white/5 border ${errors.car_model ? 'border-red-500' : 'border-white/10'} rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#5ee7df]`}
                    placeholder="nt. 520d"
                  />
                  {errors.car_model && <p className="text-red-500 text-sm mt-1">{errors.car_model}</p>}
                </div>

                <div>
                  <label className="block text-sm text-white/80 mb-2">Aasta *</label>
                  <input
                    type="number"
                    name="car_year"
                    value={formData.car_year}
                    onChange={handleChange}
                    min="1900"
                    max={new Date().getFullYear() + 1}
                    className={`w-full bg-white/5 border ${errors.car_year ? 'border-red-500' : 'border-white/10'} rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#5ee7df]`}
                    placeholder="2020"
                  />
                  {errors.car_year && <p className="text-red-500 text-sm mt-1">{errors.car_year}</p>}
                </div>

                <div>
                  <label className="block text-sm text-white/80 mb-2">Registreerimisnumber *</label>
                  <input
                    type="text"
                    name="car_registration"
                    value={formData.car_registration}
                    onChange={handleChange}
                    className={`w-full bg-white/5 border ${errors.car_registration ? 'border-red-500' : 'border-white/10'} rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#5ee7df]`}
                    placeholder="123ABC"
                  />
                  {errors.car_registration && <p className="text-red-500 text-sm mt-1">{errors.car_registration}</p>}
                </div>

                <div className="md:col-span-2">
                  <label className="block text-sm text-white/80 mb-2">Läbisõit (km)</label>
                  <input
                    type="number"
                    name="car_mileage"
                    value={formData.car_mileage}
                    onChange={handleChange}
                    className="w-full bg-white/5 border border-white/10 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#5ee7df]"
                    placeholder="150000"
                  />
                </div>
              </div>
            </div>

            {/* Service Information */}
            <div className="border border-white/10 rounded-2xl p-6 bg-white/[0.02] backdrop-blur-sm">
              <h2 className="text-xl font-light text-white mb-6 flex items-center gap-2">
                <FileText size={20} className="text-[#5ee7df]" />
                Teenuse andmed
              </h2>
              
              <div className="space-y-4">
                <div>
                  <label className="block text-sm text-white/80 mb-2">Teenuse tüüp *</label>
                  <select
                    name="service_type"
                    value={formData.service_type}
                    onChange={handleChange}
                    className={`w-full bg-white/5 border ${errors.service_type ? 'border-red-500' : 'border-white/10'} rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#5ee7df]`}
                  >
                    <option value="" className="bg-[#05070F]">Vali teenus</option>
                    {serviceTypes.map(service => (
                      <option key={service} value={service} className="bg-[#05070F]">
                        {service}
                      </option>
                    ))}
                  </select>
                  {errors.service_type && <p className="text-red-500 text-sm mt-1">{errors.service_type}</p>}
                </div>

                <div>
                  <label className="block text-sm text-white/80 mb-2">Kirjeldus</label>
                  <textarea
                    name="service_description"
                    value={formData.service_description}
                    onChange={handleChange}
                    rows="4"
                    className="w-full bg-white/5 border border-white/10 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#5ee7df]"
                    placeholder="Kirjelda oma auto probleemi või teenuse detaile..."
                  />
                </div>
              </div>
            </div>

            {/* Booking Time */}
            <div className="border border-white/10 rounded-2xl p-6 bg-white/[0.02] backdrop-blur-sm">
              <h2 className="text-xl font-light text-white mb-6 flex items-center gap-2">
                <Calendar size={20} className="text-[#5ee7df]" />
                Broneeringu aeg
              </h2>
              
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm text-white/80 mb-2">Kuupäev *</label>
                  <input
                    type="date"
                    name="booking_date"
                    value={formData.booking_date}
                    onChange={handleChange}
                    min={getMinDate()}
                    className={`w-full bg-white/5 border ${errors.booking_date ? 'border-red-500' : 'border-white/10'} rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#5ee7df]`}
                  />
                  {errors.booking_date && <p className="text-red-500 text-sm mt-1">{errors.booking_date}</p>}
                </div>

                <div>
                  <label className="flex text-sm text-white/80 mb-2 items-center gap-2">
                    <Clock size={16} />
                    Kellaaeg * (60-min sammud)
                  </label>
                  <select
                    name="booking_time"
                    value={formData.booking_time}
                    onChange={handleChange}
                    disabled={!formData.booking_date}
                    className={`w-full bg-white/5 border ${errors.booking_time ? 'border-red-500' : 'border-white/10'} rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#5ee7df] disabled:opacity-50`}
                  >
                    <option value="" className="bg-[#05070F]">Vali aeg</option>
                    {availableSlots.map(slot => (
                      <option key={slot} value={slot} className="bg-[#05070F]">
                        {slot.substring(0, 5)}
                      </option>
                    ))}
                  </select>
                  {errors.booking_time && <p className="text-red-500 text-sm mt-1">{errors.booking_time}</p>}
                  {!formData.booking_date && (
                    <p className="text-white/40 text-sm mt-1">Vali esmalt kuupäev</p>
                  )}
                </div>
              </div>
            </div>

            {/* Submit Status */}
            <AnimatePresence>
              {submitStatus && (
                <motion.div
                  initial={{ opacity: 0, y: -10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0 }}
                  className={`border rounded-lg p-4 flex items-center gap-3 ${
                    submitStatus.type === 'success' 
                      ? 'bg-green-500/10 border-green-500/50 text-green-400' 
                      : 'bg-red-500/10 border-red-500/50 text-red-400'
                  }`}
                >
                  {submitStatus.type === 'success' ? (
                    <CheckCircle size={20} />
                  ) : (
                    <XCircle size={20} />
                  )}
                  <p>{submitStatus.message}</p>
                </motion.div>
              )}
            </AnimatePresence>

            {/* Submit Button */}
            <button
              type="submit"
              disabled={isSubmitting}
              className="w-full bg-[#5ee7df] text-[#05070F] font-semibold py-4 rounded-lg hover:bg-[#4dd5cc] transition-colors disabled:opacity-50 disabled:cursor-not-allowed uppercase tracking-wider"
            >
              {isSubmitting ? 'Saadan...' : 'Saada Broneering'}
            </button>

            <p className="text-white/40 text-sm text-center">
              * Kohustuslikud väljad<br />
              Broneering vajab kinnitust. Võtame teiega ühendust 24 tunni jooksul.
            </p>
          </form>
        </motion.div>
      </div>
    </div>
  );
}

export default BookingForm;
