import React from 'react';
import {
  BlogPostLayout,
  BlogSection,
  BlogParagraph,
  BlogStrong,
} from '../../src/components/BlogPostLayout';

export default function BlogHammasrihmaVahetus() {
  return (
    <BlogPostLayout
      title="Hammasrihma vahetus – miks „umbes“ ei tööta?"
      description="Hammasrihma vahetusintervall ei ole soovituslik. Selgitame, mis juhtub, kui venitada rihm üle tootja piiride ja miks see lõpeb sageli kalli mootoriremondiga."
      category="Mootorihooldus"
      publishedAt="2024-11-15"
      readTime="5 min"
      slug="hammasrihma-vahetus"
      featuredImage="/autohooldus-tallinnas-premium.webp"
    >
      <BlogParagraph>
            Hammasrihma puhul ei kehti „sõidame veel ühe hooaja“ taktika. <BlogStrong>Rihm puruneb ootamatult</BlogStrong> ja tagajärg on enamikel mootoritel sama: ventiilid ja kolvid kohtuvad. See tähendab suurt arvet.
          </BlogParagraph>

          <BlogSection title="Tootja intervall: kilomeetrid ja aastad">
          <BlogParagraph>
            Enamik tootjaid annab hammasrihmale nii <BlogStrong>läbisõidu piiri</BlogStrong> kui ka <BlogStrong>aja piiri</BlogStrong>. Vanematel autodel on tihti kilomeetreid vähem, aga aastaid rohkem. Kummi ja kiud <BlogStrong>vananevad ka seistes</BlogStrong>, mitte ainult sõites.
          </BlogParagraph>

</BlogSection>

          <BlogSection title="Mis juhtub, kui rihm puruneb?">
          <BlogParagraph>
            Interference-tüüpi mootorites tähendab rihma purunemine, et kolb tabab avatud ventiili, ventiil kõverub ning kahjustuvad plokikaas ja kolvid. See ei ole enam hammasrihma remont, vaid <BlogStrong>mootori kapitaalremont või vahetus</BlogStrong>.
          </BlogParagraph>

</BlogSection>

          <BlogSection title="Kasutatud auto ja teadmata ajalooga rihm">
          <BlogParagraph>
            Kui auto ostes puudub selge tõend rihma vahetuse kohta, tuleb lähtuda halvimast ja planeerida töö kohe. Ilma tõenduseta on <BlogStrong>rihm teadmata seisus</BlogStrong>.
          </BlogParagraph>

</BlogSection>

          <BlogSection title="Miks visuaalne vaatamine ei piisa?">
          <BlogParagraph>
            Rihm võib välja näha korras, kuid sisemine kiud võib olla väsinud. Mikropragud peituvad hammaste juures ning niiskus, õli ja temperatuur teevad oma töö tasapisi. Seetõttu ei saa üksnes välimusele toetuda.
          </BlogParagraph>

</BlogSection>

          <BlogSection title="Kokkuvõte: hammasrihm ei küsi, kas sul on parasjagu raha">
          <BlogParagraph>
            <BlogStrong>Hammasrihma vahetus</BlogStrong> õigel ajal on odav kindlustus. Kui rihm puruneb, ei küsi mootor, kas on palgapäev või mitte – ta lihtsalt laguneb. Seetõttu tasub intervalli järgida ja planeerida vahetus teadlikult ette.
          </BlogParagraph>
        
</BlogSection>
    </BlogPostLayout>
  );
}
