import React, { useEffect, useMemo, useRef, useState } from 'react';
import axios from 'axios';
import './nisbel-chat.css';

const OPENAI_API_URL = 'https://api.openai.com/v1/chat/completions';
const OPENAI_MODEL = 'gpt-4o-mini';
const BACKEND_ENDPOINT = '/api/nisbel-chat';
const BACKEND_URL = import.meta.env.VITE_API_URL || 'http://localhost:3001';

const SYSTEM_PROMPT = `
Sa oled Nisbel Autostuudio teenindusnõustaja – autoremondi ja diagnostika töökoja virtuaalne abiline Tallinnas (nisbel.ee).

ALUSTA ALATI EESTI KEELES.
Kui kasutaja vastab teises keeles (vene või inglise keeles), jätka tema keeles. Kui ta vahetab tagasi eesti keelele, jätka eesti keeles.

PEAMINE EESMÄRK
- Mõista kasutaja auto probleemi.
- Selgitada seda lihtsalt ja arusaadavalt.
- Suunata diagnostika või remondi broneerimisele Nisbel Autostuudios.
- Koguda kogu vajalik info broneerimiseks.
- Pakkuda saadaolevaid aegu 60-minutiliste sammudega (24/7 vastuvõtt).
- Vajadusel julgusta klienti, et olete ülimalt paindlikud ja leiate talle kindlasti sobiva lahenduse (aeg, töömaht, remondivõimalused).

BRONEERIMISE ANDMED (KOHUSTUSLIKUD)
1. Kliendi nimi
2. Telefon
3. E-post
4. Auto mark ja mudel
5. Auto aasta
6. Auto registreerimisnumber
7. Läbisõit (km)
8. Probleemi/teenuse kirjeldus
9. Eelistatud kuupäev (DD.MM.YYYY)
10. Eelistatud kellaaeg (00:00-23:00, 60-min sammud)

KUI KÕIK ANDMED KOGUTUD:
Vasta täpselt sellises formaadis:
BOOKING_REQUEST:{
  "customer_name": "...",
  "customer_email": "...",
  "customer_phone": "...",
  "car_make": "...",
  "car_model": "...",
  "car_year": "...",
  "car_registration": "...",
  "car_mileage": "...",
  "service_description": "...",
  "booking_date": "YYYY-MM-DD",
  "booking_time": "HH:00:00"
}

HINNAINFO REEGEL
- Kui kasutaja küsib töötunni hinda, vasta selgelt:
  "Meie töötunni tasu on 50 € + km."
- Ära paku muid konkreetseid hindu (detailid, paketid, remondid).
- Lisa alati, et lõplik maksumus selgub diagnostika käigus ja sõltub auto seisukorrast, mudelist ning probleemist.

KUIDAS VESTLUST JUHTIDA
1) Alusta igat vestlust nii:
   "Tere! Palun kirjelda oma auto mark, mudel, aasta ja mis muret teeb?"
2) Küsi seejärel täpsustusi:
   - auto mark, mudel, aasta, kütus, käigukast
   - läbisõit
   - registreerimisnumber
   - sümptomid (mis juhtub, millal, kui kaua)
   - hoiatus- või veatulukesed, veakoodid
   - varasemad remondid
3) Selgita võimalikke põhjuseid kõrgel tasemel (mitte lõplik diagnoos).
4) Paku järgmiseks sammuks diagnostikat või remonti Nisbel Autostuudios.
5) Küsi eelistatud kuupäev ja kellaaeg (00:00-23:00, iga täistund saadaval).
6) Kui kõik andmed olemas, esita BOOKING_REQUEST JSON.

REEGLID JA OHUTUS
- Ära anna lõplikku diagnoosi – selgita, et see selgub diagnostika käigus töökojas.
- Ole ohutuse osas tähelepanelik (pidurid, veermik, mootor, ülekuumenemine, rooliviga jne); vajadusel soovita mitte edasi sõita ja pöörduda kiiresti töökotta.
- Ära küsi tundlikke isikuandmeid (ID-number, pangainfo jm).
- Kui sa ei ole milleski kindel või info puudub, ütle seda ausalt ja suuna diagnostikasse.
`;

const GREETING =
  'Tere! 👋 Olen Nisbel Autostuudio virtuaalne teenindusnõustaja. ' +
  'Palun kirjelda oma auto mark, mudel, aasta ja mis muret teeb. ' +
  'Küsin sinult kindlasti ka auto registrinumbri, et saaksime sind hiljem täpsemalt aidata. ' +
  'Oleme väga paindlikud ning leiame sulle kindlasti sobiva lahenduse aja ja tööde osas.';

const htmlFromText = (text) =>
  text.split('\n').map((line, index, arr) => (
    <React.Fragment key={`${line}-${index}`}>
      {line}
      {index < arr.length - 1 && <br />}
    </React.Fragment>
  ));

function NisbelChatWidget() {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [isSending, setIsSending] = useState(false);
  const [showTyping, setShowTyping] = useState(false);
  const [conversation, setConversation] = useState([{ role: 'system', content: SYSTEM_PROMPT }]);
  const [visibleMessages, setVisibleMessages] = useState([]);
  const [sessionId] = useState(() => `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`);
  const messagesRef = useRef(null);
  
  // Draggable and resizable state
  const [position, setPosition] = useState({ x: 20, y: 20 });
  const [size, setSize] = useState({ width: 400, height: 600 });
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const windowRef = useRef(null);

  const apiKey = useMemo(() => import.meta.env.VITE_OPENAI_API_KEY || '', []);

  // Log API key availability (only first 10 chars for security)
  useEffect(() => {
    console.log('Nisbel Chat Widget: API key available:', apiKey ? `${apiKey.substring(0, 10)}...` : 'NO KEY');
    console.log('Using model:', OPENAI_MODEL);
  }, [apiKey]);

  // Handle dragging
  useEffect(() => {
    const handleMouseMove = (e) => {
      if (isDragging) {
        setPosition({
          x: e.clientX - dragOffset.x,
          y: e.clientY - dragOffset.y
        });
      } else if (isResizing) {
        const newWidth = Math.max(300, e.clientX - position.x);
        const newHeight = Math.max(400, e.clientY - position.y);
        setSize({ width: newWidth, height: newHeight });
      }
    };

    const handleMouseUp = () => {
      setIsDragging(false);
      setIsResizing(false);
    };

    if (isDragging || isResizing) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
      return () => {
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
      };
    }
  }, [isDragging, isResizing, dragOffset, position]);

  const handleHeaderMouseDown = (e) => {
    if (e.target.id === 'nisbel-chat-close') return;
    setIsDragging(true);
    const rect = windowRef.current.getBoundingClientRect();
    setDragOffset({
      x: e.clientX - rect.left,
      y: e.clientY - rect.top
    });
  };

  const handleResizeMouseDown = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setIsResizing(true);
  };

  useEffect(() => {
    if (messagesRef.current) {
      messagesRef.current.scrollTop = messagesRef.current.scrollHeight;
    }
  }, [visibleMessages, showTyping]);

  const toggleWindow = () => {
    setIsOpen((prev) => {
      const next = !prev;
      if (next && visibleMessages.length === 0) {
        addAssistantMessage(GREETING);
      }
      return next;
    });
  };

  const addAssistantMessage = (content) => {
    setConversation((prev) => [...prev, { role: 'assistant', content }]);
    setVisibleMessages((prev) => [...prev, { role: 'assistant', content }]);
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    const trimmed = input.trim();
    if (!trimmed || isSending) return;

    setInput('');
    const userMessage = { role: 'user', content: trimmed };
    setVisibleMessages((prev) => [...prev, userMessage]);
    const updatedConversation = [...conversation, userMessage];
    setConversation(updatedConversation);

    await sendToModel(updatedConversation);
  };

  const sendToModel = async (currentConversation) => {
    setIsSending(true);
    setShowTyping(true);

    try {
      let assistantText = '';

      if (apiKey) {
        console.log('Using direct OpenAI API');
        const response = await fetch(OPENAI_API_URL, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${apiKey}`,
          },
          body: JSON.stringify({
            model: OPENAI_MODEL,
            messages: currentConversation,
            temperature: 0.4,
          }),
        });

        if (!response.ok) {
          const errorData = await response.json();
          console.error('OpenAI API error:', errorData);
          throw new Error(`OpenAI API error: ${errorData.error?.message || response.statusText}`);
        }

        const data = await response.json();
        assistantText = data?.choices?.[0]?.message?.content?.trim() || '';
      } else {
        console.log('Using backend API');
        const response = await fetch(`${BACKEND_URL}${BACKEND_ENDPOINT}`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ messages: currentConversation }),
        });

        if (!response.ok) {
          throw new Error(`Backend request failed: ${response.statusText}`);
        }

        const data = await response.json();
        assistantText =
          data?.reply ||
          data?.choices?.[0]?.message?.content?.trim() ||
          '';
      }

      if (!assistantText) {
        assistantText =
          'Vabandust, hetkel ei saanud vastust moodustada. Palun proovi uuesti või võta ühendust Nisbel Autostuudioga.';
      }

      // Check if assistant is requesting booking
      if (assistantText.includes('BOOKING_REQUEST:')) {
        const jsonMatch = assistantText.match(/BOOKING_REQUEST:(\{[\s\S]*?\})/);
        if (jsonMatch) {
          try {
            const bookingData = JSON.parse(jsonMatch[1]);
            await createBooking(bookingData);
            assistantText = assistantText.replace(/BOOKING_REQUEST:[\s\S]*?\}/, 
              '✅ Broneering on edukalt esitatud! Nisbel Autostuudio meeskond vaatab selle üle ja võtab teiega peagi ühendust kinnitamiseks. Täname!'
            );
          } catch (err) {
            console.error('Failed to parse or create booking:', err);
          }
        }
      }

      // Save messages to database
      await saveMessages(currentConversation, assistantText);

      addAssistantMessage(assistantText);
    } catch (error) {
      console.error('Nisbel chat widget error', error);
      addAssistantMessage(
        'Vabandust, hetkel ei saa ma vastust tuua. Palun proovi hiljem uuesti või võta ühendust Nisbel Autostuudioga telefoni või e-posti teel.'
      );
    } finally {
      setIsSending(false);
      setShowTyping(false);
    }
  };

  const createBooking = async (bookingData) => {
    try {
      await axios.post(`${BACKEND_URL}/api/bookings`, bookingData);
      console.log('Booking created successfully');
    } catch (error) {
      console.error('Failed to create booking:', error);
      throw error;
    }
  };

  const saveMessages = async (conversationHistory, assistantResponse) => {
    try {
      // Save user message
      const lastUserMessage = conversationHistory[conversationHistory.length - 1];
      if (lastUserMessage?.role === 'user') {
        await axios.post(`${BACKEND_URL}/api/chat`, {
          role: 'user',
          content: lastUserMessage.content,
          session_id: sessionId
        });
      }

      // Save assistant response
      await axios.post(`${BACKEND_URL}/api/chat`, {
        role: 'assistant',
        content: assistantResponse,
        session_id: sessionId
      });
    } catch (error) {
      console.error('Failed to save chat messages:', error);
    }
  };

  return (
    <>
      <div id='nisbel-chat-launcher' onClick={toggleWindow}>
        💬 Küsi nõu
      </div>

      <div
        ref={windowRef}
        id='nisbel-chat-window'
        style={{ 
          display: isOpen ? 'flex' : 'none',
          position: 'fixed',
          left: `${position.x}px`,
          top: `${position.y}px`,
          width: `${size.width}px`,
          height: `${size.height}px`,
          cursor: isDragging ? 'grabbing' : 'default'
        }}
        role='dialog'
        aria-label='Nisbel Autostuudio vestlusaken'
      >
        <div 
          className='nisbel-chat-header'
          onMouseDown={handleHeaderMouseDown}
          style={{ cursor: isDragging ? 'grabbing' : 'grab' }}
        >
          <div>
            <div className='nisbel-chat-title'>Nisbel Autostuudio</div>
            <div className='nisbel-chat-subtitle'>Virtuaalne teenindusnõustaja</div>
          </div>
          <button id='nisbel-chat-close' onClick={() => setIsOpen(false)} aria-label='Sulge vestlus'>
            &times;
          </button>
        </div>

        <div id='nisbel-chat-messages' ref={messagesRef}>
          {visibleMessages.map((message, index) => (
            <div
              key={`message-${index}`}
              className={`nisbel-message ${
                message.role === 'user' ? 'nisbel-message-user' : 'nisbel-message-assistant'
              }`}
            >
              <span>{htmlFromText(message.content)}</span>
            </div>
          ))}
          {showTyping && <div className='nisbel-typing'>Assistent kirjutab...</div>}
        </div>

        <form id='nisbel-chat-form' onSubmit={handleSubmit}>
          <textarea
            id='nisbel-chat-input'
            rows={2}
            placeholder='Kirjelda oma auto mark, mudel, aasta ja mis muret teeb...'
            value={input}
            onChange={(event) => setInput(event.target.value)}
          />
          <button type='submit' disabled={isSending}>
            {isSending ? 'Saadan...' : 'Saada'}
          </button>
        </form>
        
        {/* Resize handle */}
        <div
          onMouseDown={handleResizeMouseDown}
          style={{
            position: 'absolute',
            right: 0,
            bottom: 0,
            width: '20px',
            height: '20px',
            cursor: 'nwse-resize',
            background: 'linear-gradient(135deg, transparent 50%, rgba(255,255,255,0.1) 50%)',
            borderBottomRightRadius: '8px'
          }}
        />
      </div>
    </>
  );
}

export default NisbelChatWidget;
