import React from 'react';
import {
  BlogPostLayout,
  BlogSection,
  BlogParagraph,
  BlogStrong,
} from '../../src/components/BlogPostLayout';

export default function BlogDpfJaLinnasoit() {
  return (
    <BlogPostLayout
      title="DPF filtreerib, kuni ei filtreeri enam – kuidas linnasõit vanema diisli tapab?"
      description="Selgitame, kuidas lühikesed linnasõidud ummistavad DPF-i, miks regenereerimine ei õnnestu ja millal on veel võimalik filter päästa."
      category="Mootorihooldus"
      publishedAt="2024-11-15"
      readTime="5 min"
      slug="dpf-ja-linnasoit"
      featuredImage="/autohooldus-tallinnas-premium.webp"
    >
      <BlogParagraph>
            Diiselmootor ja <BlogStrong>DPF</BlogStrong> saavad hästi läbi seni, kuni auto saab aeg-ajalt korralikult kuuma. Puhas linnasõit, lühikesed otsad ja külmad käivitused on kombinatsioon, mis tapab filtri vaikselt, aga kindlalt.
          </BlogParagraph>

          <BlogSection title="Kuidas DPF töötab?">
          <BlogParagraph>DPF püüab kinni <BlogStrong>tahma ja osakesed</BlogStrong> heitgaasidest, teatud intervalliga teeb auto <BlogStrong>regenereerimist</BlogStrong> ja põletab tahma CO₂-ks, et filter jääks töövõimeliseks.</BlogParagraph>

</BlogSection>

          <BlogSection title="Miks linnasõit on halb?">
          <BlogParagraph>
            Regenereerimine vajab piisavalt kõrget heitgaasi temperatuuri, aega ja ühtlast kiirust. Lühikesed otsad ja start-stop sõidud tähendavad, et DPF ei jõua kunagi lõpuni regenereerida ja kogub ainult juurde.
          </BlogParagraph>

</BlogSection>

          <BlogSection title="Tüüpilised sümptomid">
          <ul>
            <li>mootor läheb <BlogStrong>limp mode’i</BlogStrong>;</li>
            <li>tõuseb <BlogStrong>kütusekulu</BlogStrong>;</li>
            <li>ventikas jookseb tihti järgi;</li>
            <li>armatuuris ilmub DPF või check engine hoiatus.</li>
          </ul>

</BlogSection>

          <BlogSection title="Sundregenereerimine ei lahenda kõike">
          <BlogParagraph>
            Sundregenereerimine aitab, kui filter pole veel täis tuhka ja lahendatakse ka põhjus (lekked, sensorid, sõiduprofiil). Kui jätkad samamoodi linnasõite, on DPF varsti jälle hädas.
          </BlogParagraph>

</BlogSection>

          <BlogSection title="Kuidas vanema diisliga targalt toimetada?">
          <ul>
            <li>korra-kaks nädalas tee <BlogStrong>pikem maanteesõit</BlogStrong>;</li>
            <li>kasuta õiget <BlogStrong>ACEA/ tootja nõudega õli</BlogStrong>;</li>
            <li>pööra tähelepanu auto käitumise muutustele.</li>
          </ul>

</BlogSection>

          <BlogSection title="Millal on veel päästa ja millal on hilja?">
          <BlogParagraph>Päästa saab, kui filter on tahmast ummistunud ja reageerid esimeste sümptomite ajal. Hilja on siis, kui kärg on läbi põlenud või mehaaniliselt kahjustunud.</BlogParagraph>

</BlogSection>

          <BlogSection title="Kokkuvõte">
          <BlogParagraph>
            <BlogStrong>Vanem diisel koos DPF-iga</BlogStrong> ei ole mõeldud puhtalt 2–5 km linnaringide tarbeks. Kas planeeri regulaarsed „puhastussõidud“ või mõtle, kas diisel sobib sinu kasutusprofiilile.
          </BlogParagraph>
        
</BlogSection>
    </BlogPostLayout>
  );
}
